'use client';

import { logger } from '@/lib/utils/logger';
import type { ChangeEvent, RefObject } from 'react';
import { Button, Input } from '@shop/ui';
import { useTranslation } from '../../../../../lib/i18n-client';
import { getColorHex } from '../../../../../lib/colorMap';
import { CURRENCIES, type CurrencyCode } from '../../../../../lib/currency';
import type { Attribute, GeneratedVariant } from '../types';

interface VariantBuilderProps {
  generatedVariants: GeneratedVariant[];
  attributes: Attribute[];
  selectedAttributesForVariants: Set<string>;
  isEditMode: boolean;
  hasVariantsToLoad: boolean;
  defaultCurrency: CurrencyCode;
  imageUploadLoading: boolean;
  slug: string;
  title: string;
  variantImageInputRefs: RefObject<Record<string, HTMLInputElement | null>>;
  onVariantUpdate: (updater: (prev: GeneratedVariant[]) => GeneratedVariant[]) => void;
  onVariantDelete: (variantId: string) => void;
  onVariantAdd: () => void;
  onApplyToAll: (field: 'price' | 'compareAtPrice' | 'stock' | 'sku', value: string) => void;
  onVariantImageUpload: (variantId: string, event: ChangeEvent<HTMLInputElement>) => void;
  onOpenValueModal: (modal: { variantId: string; attributeId: string } | null) => void;
  generateSlug: (title: string) => string;
}

export function VariantBuilder({
  generatedVariants,
  attributes,
  selectedAttributesForVariants,
  isEditMode,
  hasVariantsToLoad,
  defaultCurrency,
  imageUploadLoading,
  slug,
  title,
  variantImageInputRefs,
  onVariantUpdate,
  onVariantDelete,
  onVariantAdd,
  onApplyToAll,
  onVariantImageUpload,
  onOpenValueModal,
  generateSlug,
}: VariantBuilderProps) {
  const { t } = useTranslation();

  // Get attributes to show in table header
  const getAttributesToShow = (variant?: GeneratedVariant) => {
    if (selectedAttributesForVariants.size > 0) {
      return Array.from(selectedAttributesForVariants);
    }
    if (isEditMode && variant) {
      // Extract unique attribute IDs from this variant's values
      const attrIds = new Set<string>();
      variant.selectedValueIds.forEach((valueId) => {
        const attr = attributes.find((a) => a.values.some((v) => v.id === valueId));
        if (attr) attrIds.add(attr.id);
      });
      return Array.from(attrIds);
    }
    return [];
  };

  const attributesToShow = generatedVariants.length > 0 ? getAttributesToShow(generatedVariants[0]) : [];

  return (
    <div>
      <h2 className="text-xl font-semibold text-gray-900 mb-4">{t('admin.products.add.variantBuilder')}</h2>
      <div className="bg-white border border-gray-200 rounded-lg p-6 space-y-6">
        {/* Generated Variants Table */}
        {generatedVariants.length > 0 && (
          <div>
            <div className="flex items-center justify-between mb-4">
              <h3 className="text-lg font-semibold text-gray-900">
                {t('admin.products.add.generatedVariants')} ({generatedVariants.length.toString()})
              </h3>
              <div className="flex gap-2">
                <Button
                  type="button"
                  variant="outline"
                  size="sm"
                  onClick={() => {
                    const price = prompt(t('admin.products.add.enterDefaultPrice'));
                    if (price !== null) {
                      onApplyToAll('price', price);
                    }
                  }}
                >
                  {t('admin.products.add.applyPriceToAll')}
                </Button>
                <Button
                  type="button"
                  variant="outline"
                  size="sm"
                  onClick={() => {
                    const stock = prompt(t('admin.products.add.enterDefaultStock'));
                    if (stock !== null) {
                      onApplyToAll('stock', stock);
                    }
                  }}
                >
                  {t('admin.products.add.applyStockToAll')}
                </Button>
                <Button
                  type="button"
                  variant="outline"
                  size="sm"
                  onClick={() => {
                    const skuPrefix = prompt(t('admin.products.add.enterSkuPrefix'));
                    if (skuPrefix !== null) {
                      const baseSlug = skuPrefix || slug || generateSlug(title) || 'PROD';
                      onVariantUpdate((prev) =>
                        prev.map((variant) => {
                          const valueParts: string[] = [];
                          Array.from(selectedAttributesForVariants).forEach((attributeId) => {
                            const attribute = attributes.find((a) => a.id === attributeId);
                            if (!attribute) return;

                            const selectedIds = variant.selectedValueIds.filter((id) =>
                              attribute.values.some((v) => v.id === id)
                            );

                            selectedIds.forEach((valueId) => {
                              const value = attribute.values.find((v) => v.id === valueId);
                              if (value) {
                                valueParts.push(value.value.toUpperCase().replace(/\s+/g, '-'));
                              }
                            });
                          });

                          const sku =
                            valueParts.length > 0
                              ? `${baseSlug.toUpperCase()}-${valueParts.join('-')}`
                              : `${baseSlug.toUpperCase()}`;

                          return { ...variant, sku };
                        })
                      );
                    }
                  }}
                >
                  {t('admin.products.add.applySkuToAll')}
                </Button>
              </div>
            </div>

            <div className="border border-gray-300 rounded-lg" style={{ overflowX: 'hidden', overflowY: 'hidden' }}>
              <table className="w-full divide-y divide-gray-200 bg-white">
                <thead className="bg-gray-50">
                  <tr>
                    {attributesToShow.map((attributeId) => {
                      const attribute = attributes.find((a) => a.id === attributeId);
                      return attribute ? (
                        <th
                          key={attributeId}
                          className="px-2 py-2 text-left text-xs font-medium text-gray-500 uppercase tracking-wider"
                        >
                          {attribute.name}
                        </th>
                      ) : null;
                    })}
                    <th className="px-2 py-2 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                      {t('admin.products.add.price')}
                    </th>
                    <th className="px-2 py-2 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                      {t('admin.products.add.compareAtPrice')}
                    </th>
                    <th className="px-2 py-2 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                      {t('admin.products.add.stock')}
                    </th>
                    <th className="px-2 py-2 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                      {t('admin.products.add.sku')}
                    </th>
                    <th className="px-2 py-2 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                      {t('admin.products.add.image')}
                    </th>
                    <th className="px-2 py-2 text-left text-xs font-medium text-gray-500 uppercase tracking-wider w-20">
                      {t('admin.products.add.actions') || 'Actions'}
                    </th>
                  </tr>
                </thead>
                <tbody className="bg-white divide-y divide-gray-200">
                  {generatedVariants.map((variant) => {
                    const variantAttributesToShow = getAttributesToShow(variant);

                    return (
                      <tr key={variant.id} className="hover:bg-gray-50">
                        {variantAttributesToShow.map((attributeId) => {
                          const attribute = attributes.find((a) => a.id === attributeId);
                          if (!attribute) return null;

                          const isColor = attribute.key === 'color';
                          const selectedValueIds = variant.selectedValueIds.filter((id) => {
                            return attribute.values.some((v) => v.id === id);
                          });
                          const selectedValues = selectedValueIds
                            .map((valueId) => {
                              const value = attribute.values.find((v) => v.id === valueId);
                              return value
                                ? {
                                    id: value.id,
                                    label: value.label,
                                    value: value.value,
                                    colorHex: isColor ? (value.colors?.[0] || getColorHex(value.label)) : null,
                                    imageUrl: value.imageUrl || null,
                                  }
                                : null;
                            })
                            .filter((v): v is NonNullable<typeof v> => v !== null);

                          return (
                            <td key={attributeId} className="px-2 py-2 whitespace-nowrap">
                              <div className="relative">
                                <button
                                  type="button"
                                  onClick={() => {
                                    onOpenValueModal({ variantId: variant.id, attributeId });
                                  }}
                                  className="w-full text-left flex items-center gap-1 p-1.5 border border-gray-300 rounded-md hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-blue-500"
                                >
                                  <div className="flex-1 flex flex-wrap items-center gap-1 min-w-0">
                                    {selectedValues.length > 0 ? (
                                      selectedValues.map((val) => (
                                        <span
                                          key={val.id}
                                          className="inline-flex items-center gap-0.5 px-1.5 py-0.5 bg-blue-50 text-blue-700 rounded text-xs"
                                        >
                                          {val.imageUrl ? (
                                            <img
                                              src={val.imageUrl}
                                              alt={val.label}
                                              className="w-3 h-3 object-cover rounded border border-gray-300"
                                            />
                                          ) : isColor && val.colorHex ? (
                                            <span
                                              className="inline-block w-3 h-3 rounded-full border border-gray-300"
                                              style={{ backgroundColor: val.colorHex }}
                                            />
                                          ) : null}
                                          {val.label}
                                        </span>
                                      ))
                                    ) : (
                                      <span className="text-xs text-gray-500">{t('admin.products.add.valuesPlaceholder')}</span>
                                    )}
                                  </div>
                                  <svg
                                    className="w-3 h-3 text-gray-400 transition-transform flex-shrink-0"
                                    fill="none"
                                    stroke="currentColor"
                                    viewBox="0 0 24 24"
                                  >
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
                                  </svg>
                                </button>
                              </div>
                            </td>
                          );
                        })}
                        <td className="px-2 py-2 whitespace-nowrap">
                          <div className="flex items-center gap-1">
                            <Input
                              type="number"
                              value={variant.price}
                              onChange={(e) => {
                                onVariantUpdate((prev) =>
                                  prev.map((v) => (v.id === variant.id ? { ...v, price: e.target.value } : v))
                                );
                              }}
                              placeholder={t('admin.products.add.pricePlaceholder')}
                              className="w-20 text-xs"
                              min="0"
                              step="0.01"
                            />
                            <span className="text-xs text-gray-500">{CURRENCIES[defaultCurrency].symbol}</span>
                          </div>
                        </td>
                        <td className="px-2 py-2 whitespace-nowrap">
                          <div className="flex items-center gap-1">
                            <Input
                              type="number"
                              value={variant.compareAtPrice}
                              onChange={(e) => {
                                onVariantUpdate((prev) =>
                                  prev.map((v) => (v.id === variant.id ? { ...v, compareAtPrice: e.target.value } : v))
                                );
                              }}
                              placeholder={t('admin.products.add.pricePlaceholder')}
                              className="w-20 text-xs"
                              min="0"
                              step="0.01"
                            />
                            <span className="text-xs text-gray-500">{CURRENCIES[defaultCurrency].symbol}</span>
                          </div>
                        </td>
                        <td className="px-2 py-2 whitespace-nowrap">
                          <Input
                            type="number"
                            value={variant.stock}
                            onChange={(e) => {
                              onVariantUpdate((prev) =>
                                prev.map((v) => (v.id === variant.id ? { ...v, stock: e.target.value } : v))
                              );
                            }}
                            placeholder={t('admin.products.add.quantityPlaceholder')}
                            className="w-16 text-xs"
                            min="0"
                          />
                        </td>
                        <td className="px-2 py-2 whitespace-nowrap">
                          <Input
                            type="text"
                            value={variant.sku}
                            onChange={(e) => {
                              onVariantUpdate((prev) =>
                                prev.map((v) => (v.id === variant.id ? { ...v, sku: e.target.value } : v))
                              );
                            }}
                            placeholder={t('admin.products.add.autoGenerated')}
                            className="w-24 text-xs"
                          />
                        </td>
                        <td className="px-2 py-2 whitespace-nowrap">
                          <div className="flex items-center gap-2">
                            {variant.image ? (
                              <div className="relative inline-block">
                                <img
                                  src={variant.image}
                                  alt="Variant image"
                                  className="w-12 h-12 object-cover border border-gray-300 rounded-md"
                                />
                                <button
                                  type="button"
                                  onClick={() => {
                                    onVariantUpdate((prev) =>
                                      prev.map((v) => (v.id === variant.id ? { ...v, image: null } : v))
                                    );
                                    if (variantImageInputRefs.current?.[variant.id]) {
                                      variantImageInputRefs.current[variant.id]!.value = '';
                                    }
                                  }}
                                  className="absolute -top-1 -right-1 bg-red-500 text-white rounded-full p-0.5 hover:bg-red-600 transition-colors"
                                  title={t('admin.products.add.removeImage')}
                                >
                                  <svg className="w-2.5 h-2.5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                                  </svg>
                                </button>
                              </div>
                            ) : (
                              <button
                                type="button"
                                onClick={() => variantImageInputRefs.current?.[variant.id]?.click()}
                                disabled={imageUploadLoading}
                                className="px-2 py-1 text-xs font-medium text-gray-700 bg-white border border-gray-300 rounded-md hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-blue-500 disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-1"
                              >
                                <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
                                </svg>
                                <span className="hidden sm:inline">
                                  {imageUploadLoading ? t('admin.products.add.uploading') : t('admin.products.add.uploadImage')}
                                </span>
                                <span className="sm:hidden">+</span>
                              </button>
                            )}
                            <input
                              ref={(el) => {
                                if (variantImageInputRefs.current) {
                                  variantImageInputRefs.current[variant.id] = el;
                                }
                              }}
                              type="file"
                              accept="image/*"
                              onChange={(e) => onVariantImageUpload(variant.id, e)}
                              className="hidden"
                            />
                          </div>
                        </td>
                        <td className="px-2 py-2 whitespace-nowrap">
                          <button
                            type="button"
                            onClick={() => onVariantDelete(variant.id)}
                            className="px-2 py-1 text-xs font-medium text-red-700 bg-red-50 border border-red-300 rounded-md hover:bg-red-100 focus:outline-none focus:ring-2 focus:ring-red-500 transition-colors flex items-center gap-1"
                            title={t('admin.products.add.deleteVariant') || 'Delete variant'}
                          >
                            <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                              <path
                                strokeLinecap="round"
                                strokeLinejoin="round"
                                strokeWidth={2}
                                d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"
                              />
                            </svg>
                            {t('admin.products.add.delete') || 'Delete'}
                          </button>
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>

            <div className="mt-4 flex justify-end gap-2">
              <Button type="button" variant="outline" onClick={onVariantAdd}>
                {t('admin.products.add.addVariant') || 'Add'}
              </Button>
              <Button
                type="button"
                onClick={() => {
                  logger.debug('✅ [VARIANT BUILDER] Variants ready for submission:', generatedVariants);
                }}
              >
                {t('admin.products.add.variantsReady') || 'Variants Ready'}
              </Button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

'use client';

import { logger } from '@/lib/utils/logger';
import type { ChangeEvent } from 'react';
import { processImageFile } from '../../../../../lib/utils/image-utils';
import { getErrorMessage } from '../../../../../lib/types/errors';
import type { Variant, ColorData } from '../types';
import type { GeneratedVariant } from '../types';

interface UseImageHandlingProps {
  imageUrls: string[];
  featuredImageIndex: number;
  variants: Variant[];
  generatedVariants: GeneratedVariant[];
  colorImageTarget: { variantId: string; colorValue: string } | null;
  setImageUrls: (updater: (prev: string[]) => string[]) => void;
  setFeaturedImageIndex: (index: number) => void;
  setMainProductImage: (image: string) => void;
  setVariants: (updater: (prev: Variant[]) => Variant[]) => void;
  setGeneratedVariants: (updater: (prev: GeneratedVariant[]) => GeneratedVariant[]) => void;
  setImageUploadLoading: (loading: boolean) => void;
  setImageUploadError: (error: string | null) => void;
  setColorImageTarget: (target: { variantId: string; colorValue: string } | null) => void;
  t: (key: string) => string;
}

interface UseImageHandlingReturn {
  addImageUrl: () => void;
  removeImageUrl: (index: number) => void;
  updateImageUrl: (index: number, url: string) => void;
  setFeaturedImage: (index: number) => void;
  handleUploadImages: (event: ChangeEvent<HTMLInputElement>) => Promise<void>;
  handleUploadVariantImage: (variantId: string, event: ChangeEvent<HTMLInputElement>) => Promise<void>;
  handleUploadColorImages: (event: ChangeEvent<HTMLInputElement>) => Promise<void>;
  addColorImages: (variantId: string, colorValue: string, images: string[]) => void;
}

export function useImageHandling({
  imageUrls,
  featuredImageIndex,
  variants,
  generatedVariants,
  colorImageTarget,
  setImageUrls,
  setFeaturedImageIndex,
  setMainProductImage,
  setVariants,
  setGeneratedVariants,
  setImageUploadLoading,
  setImageUploadError,
  setColorImageTarget,
  t,
}: UseImageHandlingProps): UseImageHandlingReturn {
  const addImageUrl = () => {
    setImageUrls((prev) => [...prev, '']);
  };

  const removeImageUrl = (index: number) => {
    setImageUrls((prev) => {
      const newUrls = prev.filter((_, i) => i !== index);
      let newFeaturedIndex = featuredImageIndex;
      if (index === featuredImageIndex) {
        newFeaturedIndex = 0;
      } else if (index < featuredImageIndex) {
        newFeaturedIndex = Math.max(0, featuredImageIndex - 1);
      }
      const finalFeaturedIndex = newUrls.length === 0 ? 0 : Math.min(newFeaturedIndex, newUrls.length - 1);
      const mainImage = newUrls.length > 0 && newUrls[finalFeaturedIndex] ? newUrls[finalFeaturedIndex] : '';
      setFeaturedImageIndex(finalFeaturedIndex);
      setMainProductImage(mainImage);
      return newUrls;
    });
  };

  const updateImageUrl = (index: number, url: string) => {
    setImageUrls((prev) => {
      const newUrls = [...prev];
      newUrls[index] = url;
      return newUrls;
    });
  };

  const setFeaturedImage = (index: number) => {
    if (index < 0 || index >= imageUrls.length) {
      return;
    }
    const mainImage = imageUrls[index] || '';
    setFeaturedImageIndex(index);
    setMainProductImage(mainImage);
  };

  const addColorImages = (variantId: string, colorValue: string, images: string[]) => {
    logger.debug('🖼️ [ADMIN] Adding images to color:', {
      variantId,
      colorValue,
      imagesCount: images.length,
    });

    setVariants((prev) =>
      prev.map((v) => {
        if (v.id === variantId) {
          const updatedColors = v.colors.map((c) => {
            if (c.colorValue === colorValue) {
              const uniqueNewImages = images.filter((newImg) => !c.images.includes(newImg));
              const newImages = [...c.images, ...uniqueNewImages];
              return { ...c, images: newImages };
            }
            return c;
          });
          return { ...v, colors: updatedColors };
        }
        return v;
      })
    );
  };

  const handleUploadImages = async (event: ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(event.target.files || []);
    if (files.length === 0) {
      return;
    }

    logger.debug('📸 [UPLOAD] Starting upload of', files.length, 'image(s)');
    setImageUploadLoading(true);
    setImageUploadError(null);
    try {
      const uploadedImages: string[] = [];
      const errors: string[] = [];

      const filePromises = files.map(async (file, index) => {
        try {
          if (!file.type.startsWith('image/')) {
            const errorMsg = `"${file.name}" is not an image file`;
            console.warn(`⚠️ [UPLOAD] Skipping non-image file ${index + 1}/${files.length}:`, file.name);
            return { success: false, error: errorMsg, index };
          }

          logger.debug(`📸 [UPLOAD] Processing file ${index + 1}/${files.length}:`, file.name, `(${Math.round(file.size / 1024)}KB)`);

          const base64 = await processImageFile(file, {
            maxSizeMB: 2,
            maxWidthOrHeight: 1920,
            useWebWorker: true,
            fileType: 'image/jpeg',
            initialQuality: 0.8,
          });

          if (base64 && base64.trim()) {
            logger.debug(`✅ [UPLOAD] Successfully processed file ${index + 1}/${files.length}:`, file.name);
            return { success: true, base64, index };
          } else {
            const errorMsg = `Failed to convert "${file.name}" to base64`;
            console.error(`❌ [UPLOAD] Empty base64 result for file ${index + 1}/${files.length}:`, file.name);
            return { success: false, error: errorMsg, index };
          }
        } catch (error: unknown) {
          const errorMsg = `Error processing "${file.name}": ${getErrorMessage(error) || 'Unknown error'}`;
          console.error(`❌ [UPLOAD] Error processing file ${index + 1}/${files.length}:`, file.name, error);
          return { success: false, error: errorMsg, index };
        }
      });

      const results = await Promise.allSettled(filePromises);

      results.forEach((result) => {
        if (result.status === 'fulfilled') {
          const fileResult = result.value;
          if (fileResult.success && fileResult.base64) {
            uploadedImages.push(fileResult.base64);
          } else if (!fileResult.success && fileResult.error) {
            errors.push(fileResult.error);
          }
        } else {
          const errorMsg = `Failed to process file: ${getErrorMessage(result.reason) || 'Unknown error'}`;
          errors.push(errorMsg);
          console.error(`❌ [UPLOAD] Promise rejected:`, result.reason);
        }
      });

      logger.debug('📸 [UPLOAD] Upload complete. Processed:', uploadedImages.length, 'of', files.length, 'files');
      if (errors.length > 0) {
        console.warn('⚠️ [UPLOAD] Errors during upload:', errors);
        setImageUploadError(errors.join('; '));
      }

      if (uploadedImages.length === 0) {
        setImageUploadError(t('admin.products.add.failedToProcessImages') || 'Failed to process images');
        return;
      }

      setImageUrls((prev) => {
        const newImageUrls = [...prev, ...uploadedImages];
        const newFeaturedIdx = prev.length === 0 ? 0 : featuredImageIndex;
        if (prev.length === 0 && newImageUrls.length > 0) {
          setFeaturedImageIndex(0);
          setMainProductImage(newImageUrls[0]);
        }
        return newImageUrls;
      });
    } catch (error: unknown) {
      console.error('❌ [UPLOAD] Fatal error during upload:', error);
      setImageUploadError(getErrorMessage(error) || t('admin.products.add.failedToProcessImages'));
    } finally {
      setImageUploadLoading(false);
      if (event.target) {
        event.target.value = '';
      }
    }
  };

  const handleUploadVariantImage = async (variantId: string, event: ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(event.target.files || []);
    if (files.length === 0) {
      return;
    }

    const file = files[0];
    if (!file.type.startsWith('image/')) {
      setImageUploadError(`"${file.name}" is not an image file`);
      if (event.target) {
        event.target.value = '';
      }
      return;
    }

    setImageUploadLoading(true);
    setImageUploadError(null);
    try {
      logger.debug('🖼️ [VARIANT IMAGE] Processing variant image:', {
        variantId,
        fileName: file.name,
        originalSize: `${Math.round(file.size / 1024)}KB`,
      });

      const base64 = await processImageFile(file, {
        maxSizeMB: 2,
        maxWidthOrHeight: 1920,
        useWebWorker: true,
        fileType: 'image/jpeg',
        initialQuality: 0.8,
      });

      setGeneratedVariants((prev) => prev.map((v) => (v.id === variantId ? { ...v, image: base64 } : v)));
      logger.debug('✅ [VARIANT BUILDER] Variant image uploaded and processed for variant:', variantId);
    } catch (error: unknown) {
      console.error('❌ [VARIANT IMAGE] Error processing variant image:', error);
      setImageUploadError(getErrorMessage(error) || t('admin.products.add.failedToProcessImage'));
    } finally {
      setImageUploadLoading(false);
      if (event.target) {
        event.target.value = '';
      }
    }
  };

  const handleUploadColorImages = async (event: ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(event.target.files || []);
    if (!files.length || !colorImageTarget) {
      logger.debug('⚠️ [ADMIN] No files or no color target:', { filesLength: files.length, colorImageTarget });
      if (event.target) {
        event.target.value = '';
      }
      return;
    }

    const imageFiles = files.filter((file) => file.type.startsWith('image/'));
    if (imageFiles.length === 0) {
      if (event.target) {
        event.target.value = '';
      }
      return;
    }

    try {
      setImageUploadLoading(true);
      logger.debug('📤 [ADMIN] Starting upload for color:', colorImageTarget.colorValue, 'Files:', imageFiles.length);

      const uploadedImages = await Promise.all(
        imageFiles.map(async (file, index) => {
          logger.debug(`🖼️ [COLOR IMAGE] Processing image ${index + 1}/${imageFiles.length}:`, {
            fileName: file.name,
            originalSize: `${Math.round(file.size / 1024)}KB`,
          });

          const base64 = await processImageFile(file, {
            maxSizeMB: 2,
            maxWidthOrHeight: 1920,
            useWebWorker: true,
            fileType: 'image/jpeg',
            initialQuality: 0.8,
          });

          logger.debug(`✅ [COLOR IMAGE] Image ${index + 1}/${imageFiles.length} processed, base64 length:`, base64.length);
          return base64;
        })
      );

      logger.debug('📥 [ADMIN] All images processed, adding to variant:', {
        variantId: colorImageTarget.variantId,
        colorValue: colorImageTarget.colorValue,
        imagesCount: uploadedImages.length,
      });

      addColorImages(colorImageTarget.variantId, colorImageTarget.colorValue, uploadedImages);
      logger.debug('✅ [ADMIN] Color images added to state:', uploadedImages.length);
    } catch (error: unknown) {
      console.error('❌ [ADMIN] Error uploading color images:', error);
      setImageUploadError(getErrorMessage(error) || t('admin.products.add.failedToProcessImages'));
    } finally {
      setImageUploadLoading(false);
      if (event.target) {
        event.target.value = '';
      }
      setColorImageTarget(null);
    }
  };

  return {
    addImageUrl,
    removeImageUrl,
    updateImageUrl,
    setFeaturedImage,
    handleUploadImages,
    handleUploadVariantImage,
    handleUploadColorImages,
    addColorImages,
  };
}

import { useState } from 'react';
import { apiClient } from '../../../../../lib/api-client';
import { getErrorMessage } from '../../../../../lib/types/errors';
import { useTranslation } from '../../../../../lib/i18n-client';
import type { Attribute } from '../types';

interface UseProductAttributeHandlersProps {
  attributes: Attribute[];
  setAttributes: (updater: (prev: Attribute[]) => Attribute[]) => void;
  getColorAttribute: () => Attribute | undefined;
  getSizeAttribute: () => Attribute | undefined;
}

export function useProductAttributeHandlers({
  attributes,
  setAttributes,
  getColorAttribute,
  getSizeAttribute,
}: UseProductAttributeHandlersProps) {
  const { t } = useTranslation();
  const [newColorName, setNewColorName] = useState('');
  const [newSizeName, setNewSizeName] = useState('');
  const [addingColor, setAddingColor] = useState(false);
  const [addingSize, setAddingSize] = useState(false);
  const [colorMessage, setColorMessage] = useState<{ type: 'success' | 'error'; text: string } | null>(null);
  const [sizeMessage, setSizeMessage] = useState<{ type: 'success' | 'error'; text: string } | null>(null);

  const handleAddColor = async () => {
    setColorMessage(null);
    const colorAttribute = getColorAttribute();
    if (!colorAttribute) {
      setColorMessage({ type: 'error', text: t('admin.products.add.colorAttributeNotFound') });
      return;
    }

    if (!newColorName.trim()) {
      setColorMessage({ type: 'error', text: t('admin.products.add.colorNameRequired') });
      return;
    }

    try {
      setAddingColor(true);
      const response = await apiClient.post<{ data: Attribute }>(`/api/v1/admin/attributes/${colorAttribute.id}/values`, {
        label: newColorName.trim(),
        locale: 'en',
      });
      
      if (response.data) {
        setAttributes((prev) => 
          prev.map((attr) => 
            attr.id === colorAttribute.id ? response.data : attr
          )
        );
        setColorMessage({ type: 'success', text: t('admin.products.add.colorAddedSuccess').replace('{name}', newColorName.trim()) });
        setNewColorName('');
        setTimeout(() => setColorMessage(null), 3000);
      }
    } catch (err: unknown) {
      setColorMessage({ type: 'error', text: getErrorMessage(err) || t('admin.products.add.failedToAddColor') });
    } finally {
      setAddingColor(false);
    }
  };

  const handleAddSize = async () => {
    setSizeMessage(null);
    const sizeAttribute = getSizeAttribute();
    if (!sizeAttribute) {
      setSizeMessage({ type: 'error', text: t('admin.products.add.sizeAttributeNotFound') });
      return;
    }

    if (!newSizeName.trim()) {
      setSizeMessage({ type: 'error', text: t('admin.products.add.sizeNameRequired') });
      return;
    }

    try {
      setAddingSize(true);
      const response = await apiClient.post<{ data: Attribute }>(`/api/v1/admin/attributes/${sizeAttribute.id}/values`, {
        label: newSizeName.trim(),
        locale: 'en',
      });
      
      if (response.data) {
        setAttributes((prev) => 
          prev.map((attr) => 
            attr.id === sizeAttribute.id ? response.data : attr
          )
        );
        setSizeMessage({ type: 'success', text: t('admin.products.add.sizeAddedSuccess').replace('{name}', newSizeName.trim()) });
        setNewSizeName('');
        setTimeout(() => setSizeMessage(null), 3000);
      }
    } catch (err: unknown) {
      setSizeMessage({ type: 'error', text: getErrorMessage(err) || t('admin.products.add.failedToAddSize') });
    } finally {
      setAddingSize(false);
    }
  };

  return {
    newColorName,
    setNewColorName,
    newSizeName,
    setNewSizeName,
    addingColor,
    addingSize,
    colorMessage,
    sizeMessage,
    handleAddColor,
    handleAddSize,
  };
}

import { logger } from '@/lib/utils/logger';
import { useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { useAuth } from '@/lib/auth/AuthContext';
import { apiClient } from '@/lib/api-client';
import { CURRENCIES, type CurrencyCode } from '@/lib/currency';
import type { Brand, Category, Attribute } from '../types';

interface UseProductDataLoadingProps {
  isLoggedIn: boolean;
  isAdmin: boolean;
  isLoading: boolean;
  setBrands: (brands: Brand[]) => void;
  setCategories: (categories: Category[]) => void;
  setAttributes: (attributes: Attribute[]) => void;
  setDefaultCurrency: (currency: CurrencyCode) => void;
  attributesDropdownOpen: boolean;
  setAttributesDropdownOpen: (open: boolean) => void;
  attributesDropdownRef: React.RefObject<HTMLDivElement>;
  categoriesExpanded: boolean;
  setCategoriesExpanded: (expanded: boolean) => void;
  brandsExpanded: boolean;
  setBrandsExpanded: (expanded: boolean) => void;
}

export function useProductDataLoading({
  isLoggedIn,
  isAdmin,
  isLoading,
  setBrands,
  setCategories,
  setAttributes,
  setDefaultCurrency,
  attributesDropdownOpen,
  setAttributesDropdownOpen,
  attributesDropdownRef,
  categoriesExpanded,
  setCategoriesExpanded,
  brandsExpanded,
  setBrandsExpanded,
}: UseProductDataLoadingProps) {
  const router = useRouter();

  // Auth check
  useEffect(() => {
    if (!isLoading) {
      if (!isLoggedIn || !isAdmin) {
        router.push('/admin');
        return;
      }
    }
  }, [isLoggedIn, isAdmin, isLoading, router]);

  // Close attributes dropdown when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (attributesDropdownRef.current && !attributesDropdownRef.current.contains(event.target as Node)) {
        setAttributesDropdownOpen(false);
      }
    };

    if (attributesDropdownOpen) {
      document.addEventListener('mousedown', handleClickOutside);
    }

    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, [attributesDropdownOpen, attributesDropdownRef, setAttributesDropdownOpen]);

  // Load default currency from settings
  useEffect(() => {
    const loadDefaultCurrency = async () => {
      try {
        const settingsRes = await apiClient.get<{ defaultCurrency?: string }>('/api/v1/admin/settings');
        const currency = (settingsRes.defaultCurrency || 'AMD') as CurrencyCode;
        if (currency in CURRENCIES) {
          setDefaultCurrency(currency);
          logger.debug('✅ [ADMIN] Default currency loaded:', currency);
        }
      } catch (err) {
        console.error('❌ [ADMIN] Error loading default currency:', err);
        setDefaultCurrency('AMD');
      }
    };
    
    if (isLoggedIn && isAdmin) {
      loadDefaultCurrency();
    }
  }, [isLoggedIn, isAdmin, setDefaultCurrency]);

  // Fetch brands, categories, and attributes
  useEffect(() => {
    const fetchData = async () => {
      try {
        logger.debug('📥 [ADMIN] Fetching brands, categories, and attributes...');
        const [brandsRes, categoriesRes, attributesRes] = await Promise.all([
          apiClient.get<{ data: Brand[] }>('/api/v1/admin/brands'),
          apiClient.get<{ data: Category[] }>('/api/v1/admin/categories'),
          apiClient.get<{ data: Attribute[] }>('/api/v1/admin/attributes'),
        ]);
        setBrands(brandsRes.data || []);
        setCategories(categoriesRes.data || []);
        setAttributes(attributesRes.data || []);
        logger.debug('✅ [ADMIN] Data fetched:', {
          brands: brandsRes.data?.length || 0,
          categories: categoriesRes.data?.length || 0,
          attributes: attributesRes.data?.length || 0,
        });
        // Debug: Log attributes details
        if (attributesRes.data && attributesRes.data.length > 0) {
          logger.debug('📋 [ADMIN] Attributes loaded:', attributesRes.data.map(attr => ({
            id: attr.id,
            key: attr.key,
            name: attr.name,
            valuesCount: attr.values?.length || 0,
            values: attr.values?.map(v => ({ 
              value: v.value, 
              label: v.label,
              colors: v.colors,
              colorsType: typeof v.colors,
              colorsIsArray: Array.isArray(v.colors),
              colorsLength: v.colors?.length,
              imageUrl: v.imageUrl 
            })) || []
          })));
          const colorAttr = attributesRes.data.find(a => a.key === 'color');
          const sizeAttr = attributesRes.data.find(a => a.key === 'size');
          if (!colorAttr) {
            console.warn('⚠️ [ADMIN] Color attribute not found in loaded attributes!');
          } else {
            logger.debug('✅ [ADMIN] Color attribute found:', { id: colorAttr.id, valuesCount: colorAttr.values?.length || 0 });
          }
          if (!sizeAttr) {
            console.warn('⚠️ [ADMIN] Size attribute not found in loaded attributes!');
          } else {
            logger.debug('✅ [ADMIN] Size attribute found:', { id: sizeAttr.id, valuesCount: sizeAttr.values?.length || 0 });
          }
        } else {
          console.warn('⚠️ [ADMIN] No attributes loaded! This may cause issues with variant builder.');
        }
        // Debug: Log categories with requiresSizes
        if (categoriesRes.data) {
          logger.debug('📋 [ADMIN] Categories with requiresSizes:', 
            categoriesRes.data.map(cat => ({ 
              id: cat.id, 
              title: cat.title, 
              requiresSizes: cat.requiresSizes 
            }))
          );
        }
      } catch (err: unknown) {
        console.error('❌ [ADMIN] Error fetching data:', err);
      }
    };
    fetchData();
  }, [setBrands, setCategories, setAttributes]);

  // Close category dropdown when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      const target = event.target as HTMLElement;
      if (categoriesExpanded && !target.closest('[data-category-dropdown]')) {
        setCategoriesExpanded(false);
      }
    };

    if (categoriesExpanded) {
      document.addEventListener('mousedown', handleClickOutside);
      return () => {
        document.removeEventListener('mousedown', handleClickOutside);
      };
    }
  }, [categoriesExpanded, setCategoriesExpanded]);

  // Close brand dropdown when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      const target = event.target as HTMLElement;
      if (brandsExpanded && !target.closest('[data-brand-dropdown]')) {
        setBrandsExpanded(false);
      }
    };

    if (brandsExpanded) {
      document.addEventListener('mousedown', handleClickOutside);
      return () => {
        document.removeEventListener('mousedown', handleClickOutside);
      };
    }
  }, [brandsExpanded, setBrandsExpanded]);
}

import { logger } from '@/lib/utils/logger';
/**
 * Hook for product form callbacks and event handlers
 */

import type { ChangeEvent, Dispatch, SetStateAction } from 'react';
import type { Brand, Category, Attribute, GeneratedVariant, SimpleProductFormData } from '../types';
import type { AddProductFormState } from '../utils/productFormDataBuilder';
import { generateSlug } from '../utils/productUtils';

interface UseProductFormCallbacksProps {
  formData: {
    title: string;
    slug: string;
    primaryCategoryId: string;
  };
  categories: Category[];
  selectedAttributesForVariants: Set<string>;
  selectedAttributeValueIds: Record<string, string[]>;
  generatedVariants: GeneratedVariant[];
  setFormData: Dispatch<SetStateAction<AddProductFormState>>;
  setSelectedAttributesForVariants: (value: Set<string> | ((prev: Set<string>) => Set<string>)) => void;
  setSelectedAttributeValueIds: (value: Record<string, string[]> | ((prev: Record<string, string[]>) => Record<string, string[]>)) => void;
  setGeneratedVariants: (value: GeneratedVariant[] | ((prev: GeneratedVariant[]) => GeneratedVariant[])) => void;
  setSimpleProductData: Dispatch<SetStateAction<SimpleProductFormData>>;
  checkIsClothingCategory: (categoryId: string, categories: Category[]) => boolean;
}

export function useProductFormCallbacks({
  formData,
  categories,
  selectedAttributesForVariants,
  selectedAttributeValueIds,
  generatedVariants,
  setFormData,
  setSelectedAttributesForVariants,
  setSelectedAttributeValueIds,
  setGeneratedVariants,
  setSimpleProductData,
  checkIsClothingCategory,
}: UseProductFormCallbacksProps) {
  const handleTitleChange = (e: ChangeEvent<HTMLInputElement>) => {
    const title = e.target.value;
    setFormData((prev) => ({
      ...prev,
      title,
      slug: prev.slug || generateSlug(title),
    }));
  };

  const isClothingCategory = () => checkIsClothingCategory(formData.primaryCategoryId, categories);

  const handleAttributeToggle = (attributeId: string, checked: boolean) => {
    const newSet = new Set(selectedAttributesForVariants);
    if (checked) {
      newSet.add(attributeId);
    } else {
      newSet.delete(attributeId);
      const newValueIds = { ...selectedAttributeValueIds };
      delete newValueIds[attributeId];
      setSelectedAttributeValueIds(newValueIds);
    }
    setSelectedAttributesForVariants(newSet);
  };

  const handleAttributeRemove = (attributeId: string) => {
    const newSet = new Set(selectedAttributesForVariants);
    newSet.delete(attributeId);
    const newValueIds = { ...selectedAttributeValueIds };
    delete newValueIds[attributeId];
    setSelectedAttributeValueIds(newValueIds);
    setSelectedAttributesForVariants(newSet);
  };

  const handleVariantDelete = (variantId: string) => {
    setGeneratedVariants((prev) => prev.filter((v) => v.id !== variantId));
  };

  const handleVariantAdd = () => {
    const newVariant: GeneratedVariant = {
      id: `variant-${Date.now()}-${Math.random()}`,
      selectedValueIds: [],
      price: '0.00',
      compareAtPrice: '0.00',
      stock: '0',
      sku: 'PROD',
      image: null,
    };
    setGeneratedVariants((prev) => {
      const updated = [...prev, newVariant];
      logger.debug('✅ [VARIANT BUILDER] New manual variant added:', {
        newVariantId: newVariant.id,
        totalVariants: updated.length,
        manualVariants: updated.filter((v) => v.id !== 'variant-all').length,
        autoVariants: updated.filter((v) => v.id === 'variant-all').length,
      });
      return updated;
    });
  };

  return {
    handleTitleChange,
    isClothingCategory,
    handleAttributeToggle,
    handleAttributeRemove,
    handleVariantDelete,
    handleVariantAdd,
  };
}

import { logger } from '@/lib/utils/logger';
import type { Dispatch, FormEvent, SetStateAction } from 'react';
import { useRouter } from 'next/navigation';
import { convertPrice, type CurrencyCode } from '@/lib/currency';
import type { Attribute, Variant, GeneratedVariant, Brand, Category } from '../types';
import type { AddProductFormState } from '../utils/productFormDataBuilder';
import { useBrandAndCategoryCreation } from './useBrandAndCategoryCreation';
import { useVariantConversionToFormData } from './useVariantConversionToFormData';
import { useVariantValidation } from './useVariantValidation';
import { processImagesForSubmit } from './useImageProcessingForSubmit';
import { createAndSubmitPayload } from './useProductPayloadCreation';

/** Variant object sent to admin product create/update API. */
type SubmitVariantPayload = {
  price: number;
  stock?: number;
  sku: string;
  published?: boolean;
  compareAtPrice?: number;
  color?: string;
  size?: string;
  imageUrl?: string;
  options?: Array<{ attributeKey: string; value: string; valueId?: string }>;
};

interface UseProductFormHandlersProps {
  formData: AddProductFormState;
  setFormData: Dispatch<SetStateAction<AddProductFormState>>;
  setLoading: (loading: boolean) => void;
  setBrands: Dispatch<SetStateAction<Brand[]>>;
  setCategories: Dispatch<SetStateAction<Category[]>>;
  productType: 'simple' | 'variable';
  simpleProductData: {
    price: string;
    compareAtPrice: string;
    sku: string;
    quantity: string;
  };
  selectedAttributesForVariants: Set<string>;
  generatedVariants: GeneratedVariant[];
  attributes: Attribute[];
  defaultCurrency: CurrencyCode;
  useNewBrand: boolean;
  newBrandName: string;
  useNewCategory: boolean;
  newCategoryName: string;
  isEditMode: boolean;
  productId: string | null;
  getColorAttribute: () => Attribute | undefined;
  getSizeAttribute: () => Attribute | undefined;
  isClothingCategory: () => boolean;
}

export function useProductFormHandlers({
  formData,
  setFormData,
  setLoading,
  setBrands,
  setCategories,
  productType,
  simpleProductData,
  selectedAttributesForVariants,
  generatedVariants,
  attributes,
  defaultCurrency,
  useNewBrand,
  newBrandName,
  useNewCategory,
  newCategoryName,
  isEditMode,
  productId,
  getColorAttribute,
  getSizeAttribute,
  isClothingCategory,
}: UseProductFormHandlersProps) {
  const router = useRouter();
  
  const { createBrandAndCategory } = useBrandAndCategoryCreation({
    formData,
    useNewBrand,
    newBrandName,
    useNewCategory,
    newCategoryName,
    setBrands,
    setCategories,
    setLoading,
  });

  const { convertGeneratedVariantsToFormData } = useVariantConversionToFormData({
    productType,
    selectedAttributesForVariants,
    generatedVariants,
    attributes,
    formDataSlug: formData.slug,
    setFormData,
  });

  const { validateVariants } = useVariantValidation({
    productType,
    variants: formData.variants,
    simpleProductData,
    isClothingCategory,
    setLoading,
  });


  const handleSubmit = async (e: FormEvent) => {
    e.preventDefault();
    setLoading(true);

    try {
      logger.debug('📝 [ADMIN] Submitting product form:', formData);

      // Create brand and category if needed
      const brandCategoryResult = await createBrandAndCategory();
      if (brandCategoryResult.error) {
        return;
      }
      const { finalBrandIds, finalPrimaryCategoryId, creationMessages } = brandCategoryResult;

      // Convert generated variants to formData format
      convertGeneratedVariantsToFormData();

      // Get current formData after potential update
      const currentFormData = formData.variants.length > 0 ? formData : { ...formData, variants: [] };

      // Validate variants
      if (productType === 'variable' && currentFormData.variants.length === 0) {
        setLoading(false);
        return;
      }
      if (!validateVariants()) {
        return;
      }

      // Process variants for API
      const variants: SubmitVariantPayload[] = [];
      const variantSkuSet = new Set<string>();

      if (productType === 'simple') {
        logger.debug('📦 [ADMIN] Processing Simple Product');
        const priceUSD = convertPrice(parseFloat(simpleProductData.price), defaultCurrency, 'USD');
        const compareAtPriceUSD = simpleProductData.compareAtPrice && simpleProductData.compareAtPrice.trim() !== ''
          ? convertPrice(parseFloat(simpleProductData.compareAtPrice), defaultCurrency, 'USD')
          : undefined;
        const simpleVariant: SubmitVariantPayload = {
          price: priceUSD,
          stock: parseInt(simpleProductData.quantity) || 0,
          sku: simpleProductData.sku.trim(),
          published: true,
        };
        if (compareAtPriceUSD) {
          simpleVariant.compareAtPrice = compareAtPriceUSD;
        }
        variants.push(simpleVariant);
        variantSkuSet.add(simpleProductData.sku.trim());
        logger.debug('✅ [ADMIN] Simple product variant created:', simpleVariant);
      } else {
        // Variable products variant processing (simplified - full logic remains in original)
        const useGeneratedVariants = generatedVariants.length > 0 && selectedAttributesForVariants.size > 0;
        
        if (useGeneratedVariants) {
          logger.debug('📦 [ADMIN] Using generatedVariants format:', generatedVariants.length, 'variants');
          const sizeAttribute = getSizeAttribute();
          
          generatedVariants.forEach((genVariant, variantIndex) => {
            const variantPriceUSD = convertPrice(parseFloat(genVariant.price || '0'), defaultCurrency, 'USD');
            const variantCompareAtPriceUSD = genVariant.compareAtPrice 
              ? convertPrice(parseFloat(genVariant.compareAtPrice), defaultCurrency, 'USD')
              : undefined;
            
            const attributeValueMap: Record<string, Array<{ valueId: string; value: string }>> = {};
            
            genVariant.selectedValueIds.forEach((valueId) => {
              const attribute = attributes.find(a => a.values.some(v => v.id === valueId));
              if (attribute) {
                const value = attribute.values.find(v => v.id === valueId);
                if (value) {
                  if (!attributeValueMap[attribute.key]) {
                    attributeValueMap[attribute.key] = [];
                  }
                  attributeValueMap[attribute.key].push({ valueId: value.id, value: value.value });
                }
              }
            });
            
            const attributeKeys = Object.keys(attributeValueMap);
            if (attributeKeys.length === 0) {
              const finalSku = genVariant.sku || `${currentFormData.slug || 'PROD'}-${Date.now()}-${variantIndex + 1}`;
              let uniqueSku = finalSku;
              let skuCounter = 1;
              while (variantSkuSet.has(uniqueSku)) {
                uniqueSku = `${finalSku}-${skuCounter}`;
                skuCounter++;
              }
              variantSkuSet.add(uniqueSku);
              variants.push({
                price: variantPriceUSD,
                compareAtPrice: variantCompareAtPriceUSD,
                stock: parseInt(genVariant.stock || '0') || 0,
                sku: uniqueSku,
                imageUrl: genVariant.image || undefined,
                published: true,
              });
            } else {
              const attributeValueGroups = attributeKeys.map(key => 
                attributeValueMap[key].map(v => v.valueId)
              );
              
              const generateCombinations = (groups: string[][]): string[][] => {
                if (groups.length === 0) return [[]];
                if (groups.length === 1) return groups[0].map(v => [v]);
                const [firstGroup, ...restGroups] = groups;
                const restCombinations = generateCombinations(restGroups);
                const result: string[][] = [];
                for (const value of firstGroup) {
                  for (const combination of restCombinations) {
                    result.push([value, ...combination]);
                  }
                }
                return result;
              };
              
              const combinations = generateCombinations(attributeValueGroups);
              
              combinations.forEach((combination, comboIndex) => {
                const variantOptions: Array<{ attributeKey: string; value: string; valueId?: string }> = [];
                combination.forEach((valueId) => {
                  const attribute = attributes.find(a => a.values.some(v => v.id === valueId));
                  if (attribute) {
                    const value = attribute.values.find(v => v.id === valueId);
                    if (value) {
                      variantOptions.push({ attributeKey: attribute.key, value: value.value, valueId: value.id });
                    }
                  }
                });
                
                const baseSlug = currentFormData.slug || 'PROD';
                const valueParts = variantOptions.map(opt => opt.value.toUpperCase().replace(/\s+/g, '-'));
                const skuSuffix = valueParts.length > 0 ? `-${valueParts.join('-')}` : '';
                const finalSku = genVariant.sku 
                  ? `${genVariant.sku}${skuSuffix}`
                  : `${baseSlug.toUpperCase()}-${Date.now()}-${variantIndex + 1}-${comboIndex + 1}${skuSuffix}`;
                
                let uniqueSku = finalSku;
                let skuCounter = 1;
                while (variantSkuSet.has(uniqueSku)) {
                  uniqueSku = `${finalSku}-${skuCounter}`;
                  skuCounter++;
                }
                variantSkuSet.add(uniqueSku);
                
                variants.push({
                  price: variantPriceUSD,
                  compareAtPrice: variantCompareAtPriceUSD,
                  stock: parseInt(genVariant.stock || '0') || 0,
                  sku: uniqueSku,
                  imageUrl: genVariant.image || undefined,
                  published: true,
                  options: variantOptions.length > 0 ? variantOptions : undefined,
                });
              });
            }
          });
        } else {
          // Legacy formData.variants processing (simplified)
          logger.debug('📦 [ADMIN] Using formData.variants format (legacy)');
          currentFormData.variants.forEach((variant, variantIndex) => {
            const variantPriceUSD = convertPrice(parseFloat(variant.price || '0'), defaultCurrency, 'USD');
            const baseVariantData: { price: number; published: boolean; compareAtPrice?: number } = {
              price: variantPriceUSD,
              published: true,
            };
            if (variant.compareAtPrice) {
              baseVariantData.compareAtPrice = convertPrice(parseFloat(variant.compareAtPrice), defaultCurrency, 'USD');
            }
            const colorDataArray = variant.colors || [];
            // Simplified variant processing - full logic would be in separate hook
            if (colorDataArray.length > 0) {
              colorDataArray.forEach((colorData, colorIndex) => {
                const colorSizes = colorData.sizes || [];
                const colorSizeStocks = colorData.sizeStocks || {};
                if (colorSizes.length > 0) {
                  colorSizes.forEach((size) => {
                    const stockForVariant = colorSizeStocks[size] || colorData.stock || '0';
                    const skuSuffix = colorDataArray.length > 1 || colorSizes.length > 1 
                      ? `-${colorIndex + 1}-${colorSizes.indexOf(size) + 1}` : '';
                    let finalSku = colorData.sizeLabels?.[size] || variant.sku ? `${variant.sku?.trim()}${skuSuffix}` : undefined;
                    if (!finalSku || finalSku === '') {
                      finalSku = `${currentFormData.slug || 'PROD'}-${Date.now()}-${variantIndex + 1}-${colorIndex + 1}-${colorSizes.indexOf(size) + 1}`;
                    }
                    let uniqueSku = finalSku;
                    let skuCounter = 1;
                    while (variantSkuSet.has(uniqueSku)) {
                      uniqueSku = `${finalSku}-${skuCounter}`;
                      skuCounter++;
                    }
                    variantSkuSet.add(uniqueSku);
                    const variantImageUrl = colorData.images && colorData.images.length > 0 ? colorData.images.join(',') : undefined;
                    const sizePrice = colorData.sizePrices?.[size];
                    const finalPriceRaw = sizePrice && sizePrice.trim() !== ''
                      ? parseFloat(sizePrice)
                      : (colorData.price && colorData.price.trim() !== '' ? parseFloat(colorData.price) : baseVariantData.price);
                    const finalPrice = convertPrice(finalPriceRaw, defaultCurrency, 'USD');
                    const variantOptions: Array<{ attributeKey: string; value: string; valueId?: string }> = [];
                    if (colorData.colorValue && colorData.colorValue.trim() !== '') {
                      const colorAttr = attributes.find(a => a.key === 'color');
                      const colorValue = colorAttr?.values.find(v => v.value === colorData.colorValue);
                      if (colorValue) {
                        variantOptions.push({ attributeKey: 'color', value: colorData.colorValue, valueId: colorValue.id });
                      } else {
                        variantOptions.push({ attributeKey: 'color', value: colorData.colorValue });
                      }
                    }
                    if (size && size.trim() !== '') {
                      const sizeAttr = attributes.find(a => a.key === 'size');
                      const sizeValue = sizeAttr?.values.find(v => v.value === size);
                      if (sizeValue) {
                        variantOptions.push({ attributeKey: 'size', value: size, valueId: sizeValue.id });
                      } else {
                        variantOptions.push({ attributeKey: 'size', value: size });
                      }
                    }
                    variants.push({
                      ...baseVariantData,
                      price: finalPrice,
                      color: colorData.colorValue,
                      size: size,
                      stock: parseInt(stockForVariant) || 0,
                      sku: uniqueSku,
                      imageUrl: variantImageUrl,
                      options: variantOptions.length > 0 ? variantOptions : undefined,
                    });
                  });
                }
              });
            }
          });
        }
      }

      // Final SKU validation
      const finalSkuSet = new Set<string>();
      for (let i = 0; i < variants.length; i++) {
        const variant = variants[i];
        if (!variant.sku || variant.sku.trim() === '') {
          const baseSlug = currentFormData.slug || 'PROD';
          variant.sku = `${baseSlug.toUpperCase()}-${Date.now()}-${i + 1}`;
        } else {
          variant.sku = variant.sku.trim();
        }
        let finalSku = variant.sku;
        let skuCounter = 1;
        while (finalSkuSet.has(finalSku)) {
          const baseSlug = currentFormData.slug || 'PROD';
          finalSku = `${baseSlug.toUpperCase()}-${Date.now()}-${i + 1}-${skuCounter}-${Math.random().toString(36).substr(2, 4)}`;
          skuCounter++;
        }
        variant.sku = finalSku;
        finalSkuSet.add(finalSku);
      }

      // Collect attribute IDs
      const attributeIdsSet = new Set<string>();
      const colorAttribute = getColorAttribute();
      const sizeAttribute = getSizeAttribute();
      if (colorAttribute) attributeIdsSet.add(colorAttribute.id);
      if (sizeAttribute) attributeIdsSet.add(sizeAttribute.id);
      const attributeIds = Array.from(attributeIdsSet);

      // Process images
      const { finalMedia, mainImage, processedVariants } = processImagesForSubmit({
        imageUrls: currentFormData.imageUrls,
        featuredImageIndex: currentFormData.featuredImageIndex,
        mainProductImage: currentFormData.mainProductImage,
        variants: variants,
      });
      const finalVariants = processedVariants.length > 0 ? processedVariants : variants;

      // Create and submit payload
      await createAndSubmitPayload({
        formData: currentFormData,
        finalBrandIds,
        finalPrimaryCategoryId,
        variants: finalVariants,
        attributeIds,
        finalMedia,
        mainImage,
        isEditMode,
        productId,
        creationMessages,
        setLoading,
        router,
      });
    } catch (err: unknown) {
      console.error('❌ [ADMIN] Error saving product:', err);
    } finally {
      setLoading(false);
    }
  };

  return { handleSubmit };
}

import { logger } from '@/lib/utils/logger';
import { apiClient } from '@/lib/api-client';
import { getApiLikeData, getErrorMessage } from '@/lib/types/errors';
import type { AppRouterInstance } from 'next/dist/shared/lib/app-router-context.shared-runtime';
import type { Attribute } from '../types';

interface CreateAndSubmitPayloadProps {
  formData: {
    title: string;
    slug: string;
    descriptionHtml: string;
    categoryIds: string[];
    published: boolean;
    featured: boolean;
    imageUrls: string[];
    featuredImageIndex: number;
    mainProductImage: string;
    labels: Array<{ type: string; value: string; position: string; color?: string | null }>;
  };
  finalBrandIds: string[];
  finalPrimaryCategoryId: string;
  variants: unknown[];
  attributeIds: string[];
  finalMedia: string[];
  mainImage: string | null;
  isEditMode: boolean;
  productId: string | null;
  creationMessages: string[];
  setLoading: (loading: boolean) => void;
  router: AppRouterInstance;
}

export async function createAndSubmitPayload({
  formData,
  finalBrandIds,
  finalPrimaryCategoryId,
  variants,
  attributeIds,
  finalMedia,
  mainImage,
  isEditMode,
  productId,
  creationMessages,
  setLoading,
  router,
}: CreateAndSubmitPayloadProps): Promise<void> {
  const payload: Record<string, unknown> = {
      title: formData.title,
      slug: formData.slug,
      descriptionHtml: formData.descriptionHtml || undefined,
      brandId: finalBrandIds.length > 0 ? finalBrandIds[0] : undefined,
      primaryCategoryId: finalPrimaryCategoryId || undefined,
      categoryIds: formData.categoryIds.length > 0 ? formData.categoryIds : undefined,
      published: isEditMode ? formData.published : true,
      featured: formData.featured,
      locale: 'en',
      variants: variants,
      attributeIds: attributeIds.length > 0 ? attributeIds : undefined,
    };
    
    if (finalMedia.length > 0) {
      payload.media = finalMedia;
    }
    
    if (mainImage) {
      payload.mainProductImage = mainImage;
    }

    payload.labels = (formData.labels || [])
      .filter((label) => label.value && label.value.trim() !== '')
      .map((label) => ({
        type: label.type,
        value: label.value.trim(),
        position: label.position,
        color: label.color || null,
      }));

    logger.debug('📤 [ADMIN] Sending payload:', JSON.stringify(payload, null, 2));
    
    try {
      if (isEditMode && productId) {
        const product = await apiClient.put(`/api/v1/admin/products/${productId}`, payload);
        logger.debug('✅ [ADMIN] Product updated:', product);
        const baseMessage = 'Ապրանքը հաջողությամբ թարմացվեց!';
        const extra = creationMessages.length ? `\n\n${creationMessages.join('\n')}` : '';
        alert(`${baseMessage}${extra}`);
      } else {
        const product = await apiClient.post('/api/v1/admin/products', payload);
        logger.debug('✅ [ADMIN] Product created:', product);
        const baseMessage = 'Ապրանքը հաջողությամբ ստեղծվեց!';
        const extra = creationMessages.length ? `\n\n${creationMessages.join('\n')}` : '';
        alert(`${baseMessage}${extra}`);
      }
      
      router.push('/admin/products');
    } catch (err: unknown) {
      console.error('❌ [ADMIN] Error saving product:', err);
      
      let errorMessage = isEditMode ? 'Չհաջողվեց թարմացնել ապրանքը' : 'Չհաջողվեց ստեղծել ապրանքը';
      const api = getApiLikeData(err);
      const msg = getErrorMessage(err);
      if (api.data?.detail) {
        errorMessage = api.data.detail;
      } else if (msg.includes('<!DOCTYPE') || msg.includes('<html')) {
        const mongoErrorMatch = msg.match(/MongoServerError[^<]+/);
        if (mongoErrorMatch) {
          errorMessage = `Տվյալների բազայի սխալ: ${mongoErrorMatch[0]}`;
        } else {
          errorMessage = 'Տվյալների բազայի սխալ: SKU-ն արդեն օգտագործված է կամ այլ սխալ:';
        }
      } else if (msg) {
        errorMessage = msg;
      }
      
      throw err;
    } finally {
      setLoading(false);
    }
}

'use client';

import { logger } from '@/lib/utils/logger';
import { useEffect } from 'react';
import type { Attribute, GeneratedVariant } from '../types';
import { generateSlug } from '../utils/productUtils';

interface UseVariantGenerationProps {
  selectedAttributesForVariants: Set<string>;
  selectedAttributeValueIds: Record<string, string[]>;
  attributes: Attribute[];
  generatedVariants: GeneratedVariant[];
  formDataSlug: string;
  formDataTitle: string;
  isEditMode: boolean;
  productId: string | null;
  setGeneratedVariants: (updater: (prev: GeneratedVariant[]) => GeneratedVariant[]) => void;
}

export function useVariantGeneration({
  selectedAttributesForVariants,
  selectedAttributeValueIds,
  attributes,
  generatedVariants,
  formDataSlug,
  formDataTitle,
  isEditMode,
  productId,
  setGeneratedVariants,
}: UseVariantGenerationProps) {
  const generateVariantsFromAttributes = () => {
    logger.debug('🚀 [VARIANT BUILDER] Generating single variant with all attributes...');

    const selectedAttrs = Array.from(selectedAttributesForVariants);
    if (selectedAttrs.length === 0) {
      logger.debug('⚠️ [VARIANT BUILDER] No attributes selected');
      setGeneratedVariants(() => []);
      return;
    }

    setGeneratedVariants((prev) => {
      const manuallyAddedVariants = prev.filter((v) => v.id !== 'variant-all');
      const existingAutoVariant = prev.find((v) => v.id === 'variant-all');

      if (manuallyAddedVariants.length > 0) {
        logger.debug('✅ [VARIANT BUILDER] Manual variants exist, skipping auto-generated variant');
        return manuallyAddedVariants;
      }

      const variantId = 'variant-all';
      const allSelectedValueIds: string[] = [];
      selectedAttrs.forEach((attributeId) => {
        const selectedIds = selectedAttributeValueIds[attributeId] || [];
        allSelectedValueIds.push(...selectedIds);
      });

      const baseSlug = formDataSlug || generateSlug(formDataTitle) || 'PROD';
      let sku = `${baseSlug}`;

      if (allSelectedValueIds.length > 0) {
        const valueParts: string[] = [];
        selectedAttrs.forEach((attributeId) => {
          const attribute = attributes.find((a) => a.id === attributeId);
          if (!attribute) return;

          const selectedIds = selectedAttributeValueIds[attributeId] || [];
          selectedIds.forEach((valueId) => {
            const value = attribute.values.find((v) => v.id === valueId);
            if (value) {
              valueParts.push(value.value.toUpperCase().replace(/\s+/g, '-'));
            }
          });
        });

        if (valueParts.length > 0) {
          sku = `${baseSlug}-${valueParts.join('-')}`;
        }
      }

      const autoVariant: GeneratedVariant = {
        id: variantId,
        selectedValueIds: allSelectedValueIds,
        price: existingAutoVariant?.price || '',
        compareAtPrice: existingAutoVariant?.compareAtPrice || '',
        stock: existingAutoVariant?.stock || '',
        sku: existingAutoVariant?.sku || sku,
        image: existingAutoVariant?.image || null,
      };

      const result = [autoVariant];
      logger.debug('✅ [VARIANT BUILDER] Variants updated:', {
        manuallyAdded: 0,
        autoGenerated: 1,
        total: result.length,
      });
      return result;
    });

    logger.debug('✅ [VARIANT BUILDER] Single variant generated with', selectedAttrs.length, 'attributes');
  };

  const applyToAllVariants = (field: 'price' | 'compareAtPrice' | 'stock' | 'sku', value: string) => {
    setGeneratedVariants((prev) =>
      prev.map((variant) => ({
        ...variant,
        [field]: value,
      }))
    );
  };

  useEffect(() => {
    if (isEditMode && productId && window.__productVariantsToConvert) {
      return;
    }

    if (selectedAttributesForVariants.size > 0) {
      generateVariantsFromAttributes();
    } else {
      if (!isEditMode) {
        setGeneratedVariants(() => []);
      }
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [selectedAttributesForVariants, selectedAttributeValueIds, attributes, formDataSlug, formDataTitle, isEditMode, productId]);

  return {
    generateVariantsFromAttributes,
    applyToAllVariants,
  };
}

import type { Variant } from '../types';

interface UseVariantValidationProps {
  productType: 'simple' | 'variable';
  variants: Variant[];
  simpleProductData: {
    price: string;
    sku: string;
    quantity: string;
  };
  isClothingCategory: () => boolean;
  setLoading: (loading: boolean) => void;
}

export function useVariantValidation({
  productType,
  variants,
  simpleProductData,
  isClothingCategory,
  setLoading,
}: UseVariantValidationProps) {
  const validateVariants = (): boolean => {
    // Skip variant validation for Simple products - they create variants later in the process
    if (productType === 'variable' && variants.length === 0) {
      setLoading(false);
      return false;
    }

    // Validate all variants (skip for simple products - validation is done in variant creation)
    if (productType === 'variable') {
      const skuSet = new Set<string>();
      for (const variant of variants) {
        const variantSku = variant.sku ? variant.sku.trim() : '';
        if (!variantSku || variantSku === '') {
          setLoading(false);
          return false;
        }
        
        if (skuSet.has(variantSku)) {
          setLoading(false);
          return false;
        }
        skuSet.add(variantSku);
        
        const categoryRequiresSizes = isClothingCategory();
        const colorData = variant.colors && variant.colors.length > 0 ? variant.colors : [];
        
        if (colorData.length > 0) {
          for (const colorDataItem of colorData) {
            const colorSizes = colorDataItem.sizes || [];
            const colorSizeStocks = colorDataItem.sizeStocks || {};
            
            const hasColor = colorDataItem.colorValue && colorDataItem.colorValue.trim() !== '';
            
            if (hasColor) {
              const colorPriceValue = parseFloat(colorDataItem.price || '0');
              if (!colorDataItem.price || isNaN(colorPriceValue) || colorPriceValue <= 0) {
                setLoading(false);
                return false;
              }
            } else {
              if (colorData.indexOf(colorDataItem) === 0) {
                const variantPriceValue = parseFloat(variant.price || '0');
                if (!variant.price || isNaN(variantPriceValue) || variantPriceValue <= 0) {
                  setLoading(false);
                  return false;
                }
              }
            }

            if (colorSizes.length > 0) {
              for (const size of colorSizes) {
                const stock = colorSizeStocks[size];
                if (!stock || typeof stock !== 'string' || stock.trim() === '' || parseInt(stock) < 0) {
                  setLoading(false);
                  return false;
                }
              }
            } else {
              if (!colorDataItem.stock || typeof colorDataItem.stock !== 'string' || colorDataItem.stock.trim() === '' || parseInt(colorDataItem.stock) < 0) {
                setLoading(false);
                return false;
              }
            }
          }
        }
      }
    }

    // Validate simple product fields
    if (productType === 'simple') {
      if (!simpleProductData.price || simpleProductData.price.trim() === '') {
        setLoading(false);
        return false;
      }
      if (!simpleProductData.sku || simpleProductData.sku.trim() === '') {
        setLoading(false);
        return false;
      }
      if (!simpleProductData.quantity || simpleProductData.quantity.trim() === '') {
        setLoading(false);
        return false;
      }
    }

    return true;
  };

  return { validateVariants };
}

'use client';

import { Suspense } from 'react';
import { useRouter, useSearchParams } from 'next/navigation';
import { useAuth } from '../../../../lib/auth/AuthContext';
import { useTranslation } from '../../../../lib/i18n-client';
import { PageHeader } from './components/PageHeader';
import { ValueSelectionModal } from './components/ValueSelectionModal';
import { AddProductFormContent } from './components/AddProductFormContent';
import { useProductFormState } from './hooks/useProductFormState';
import { useProductDataLoading } from './hooks/useProductDataLoading';
import { useProductEditMode } from './hooks/useProductEditMode';
import { useProductVariantConversion } from './hooks/useProductVariantConversion';
import { useVariantGeneration } from './hooks/useVariantGeneration';
import { useImageHandling } from './hooks/useImageHandling';
import { useLabelManagement } from './hooks/useLabelManagement';
import { useProductAttributeHelpers } from './hooks/useProductAttributeHelpers';
import { useProductAttributeHandlers } from './hooks/useProductAttributeHandlers';
import { useProductFormHandlers } from './hooks/useProductFormHandlers';
import { useProductFormCallbacks } from './hooks/useProductFormCallbacks';
import { isClothingCategory as checkIsClothingCategory, generateSlug } from './utils/productUtils';

function AddProductPageContent() {
  const { t } = useTranslation();
  const { isLoggedIn, isAdmin, isLoading } = useAuth();
  const router = useRouter();
  const searchParams = useSearchParams();
  const productId = searchParams.get('id');
  const isEditMode = !!productId;

  const formState = useProductFormState();

  useProductDataLoading({
    isLoggedIn,
    isAdmin,
    isLoading,
    setBrands: formState.setBrands,
    setCategories: formState.setCategories,
    setAttributes: formState.setAttributes,
    setDefaultCurrency: formState.setDefaultCurrency,
    attributesDropdownOpen: formState.attributesDropdownOpen,
    setAttributesDropdownOpen: formState.setAttributesDropdownOpen,
    attributesDropdownRef: formState.attributesDropdownRef,
    categoriesExpanded: formState.categoriesExpanded,
    setCategoriesExpanded: formState.setCategoriesExpanded,
    brandsExpanded: formState.brandsExpanded,
    setBrandsExpanded: formState.setBrandsExpanded,
  });

  useProductEditMode({
    productId,
    isLoggedIn,
    isAdmin,
    attributes: formState.attributes,
    defaultCurrency: formState.defaultCurrency,
    setLoadingProduct: formState.setLoadingProduct,
    setFormData: formState.setFormData,
    setUseNewBrand: formState.setUseNewBrand,
    setUseNewCategory: formState.setUseNewCategory,
    setNewBrandName: formState.setNewBrandName,
    setNewCategoryName: formState.setNewCategoryName,
    setHasVariantsToLoad: formState.setHasVariantsToLoad,
    setProductType: formState.setProductType,
    setSimpleProductData: formState.setSimpleProductData,
  });

  useProductVariantConversion({
    productId,
    attributes: formState.attributes,
    defaultCurrency: formState.defaultCurrency,
    setSelectedAttributesForVariants: formState.setSelectedAttributesForVariants,
    setSelectedAttributeValueIds: formState.setSelectedAttributeValueIds,
    setGeneratedVariants: formState.setGeneratedVariants,
    setHasVariantsToLoad: formState.setHasVariantsToLoad,
  });

  const { applyToAllVariants } = useVariantGeneration({
    selectedAttributesForVariants: formState.selectedAttributesForVariants,
    selectedAttributeValueIds: formState.selectedAttributeValueIds,
    attributes: formState.attributes,
    generatedVariants: formState.generatedVariants,
    formDataSlug: formState.formData.slug,
    formDataTitle: formState.formData.title,
    isEditMode,
    productId,
    setGeneratedVariants: formState.setGeneratedVariants,
  });

  const {
    handleTitleChange,
    isClothingCategory,
    handleAttributeToggle,
    handleAttributeRemove,
    handleVariantDelete,
    handleVariantAdd,
  } = useProductFormCallbacks({
    formData: formState.formData,
    categories: formState.categories,
    selectedAttributesForVariants: formState.selectedAttributesForVariants,
    selectedAttributeValueIds: formState.selectedAttributeValueIds,
    generatedVariants: formState.generatedVariants,
    setFormData: formState.setFormData,
    setSelectedAttributesForVariants: formState.setSelectedAttributesForVariants,
    setSelectedAttributeValueIds: formState.setSelectedAttributeValueIds,
    setGeneratedVariants: formState.setGeneratedVariants,
    setSimpleProductData: formState.setSimpleProductData,
    checkIsClothingCategory,
  });

  const {
    addImageUrl,
    removeImageUrl,
    setFeaturedImage,
    handleUploadImages,
    handleUploadVariantImage,
  } = useImageHandling({
    imageUrls: formState.formData.imageUrls,
    featuredImageIndex: formState.formData.featuredImageIndex,
    variants: formState.formData.variants,
    generatedVariants: formState.generatedVariants,
    colorImageTarget: formState.colorImageTarget,
    setImageUrls: (updater) => formState.setFormData((prev) => ({ ...prev, imageUrls: updater(prev.imageUrls) })),
    setFeaturedImageIndex: (index) => formState.setFormData((prev) => ({ ...prev, featuredImageIndex: index })),
    setMainProductImage: (image) => formState.setFormData((prev) => ({ ...prev, mainProductImage: image })),
    setVariants: (updater) => formState.setFormData((prev) => ({ ...prev, variants: updater(prev.variants) })),
    setGeneratedVariants: formState.setGeneratedVariants,
    setImageUploadLoading: formState.setImageUploadLoading,
    setImageUploadError: formState.setImageUploadError,
    setColorImageTarget: formState.setColorImageTarget,
    t,
  });

  const { addLabel, removeLabel, updateLabel } = useLabelManagement(
    formState.formData.labels,
    (updater) => formState.setFormData((prev) => ({ ...prev, labels: updater(prev.labels) }))
  );

  const { getColorAttribute, getSizeAttribute } = useProductAttributeHelpers({
    attributes: formState.attributes,
  });

  useProductAttributeHandlers({
    attributes: formState.attributes,
    setAttributes: formState.setAttributes,
    getColorAttribute,
    getSizeAttribute,
  });

  const { handleSubmit } = useProductFormHandlers({
    formData: formState.formData,
    setFormData: formState.setFormData,
    setLoading: formState.setLoading,
    setBrands: formState.setBrands,
    setCategories: formState.setCategories,
    productType: formState.productType,
    simpleProductData: formState.simpleProductData,
    selectedAttributesForVariants: formState.selectedAttributesForVariants,
    generatedVariants: formState.generatedVariants,
    attributes: formState.attributes,
    defaultCurrency: formState.defaultCurrency,
    useNewBrand: formState.useNewBrand,
    newBrandName: formState.newBrandName,
    useNewCategory: formState.useNewCategory,
    newCategoryName: formState.newCategoryName,
    isEditMode,
    productId,
    getColorAttribute,
    getSizeAttribute,
    isClothingCategory,
  });

  if (isLoading || formState.loadingProduct) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-gray-900 mx-auto mb-4"></div>
          <p className="text-gray-600">
            {formState.loadingProduct ? t('admin.products.add.loadingProduct') : t('admin.products.add.loading')}
          </p>
        </div>
      </div>
    );
  }

  if (!isLoggedIn || !isAdmin) {
    return null;
  }

  return (
    <div className="min-h-screen bg-gray-50 py-8">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div>
          <PageHeader isEditMode={isEditMode} />

          <AddProductFormContent
            formData={formState.formData}
            productType={formState.productType}
            simpleProductData={formState.simpleProductData}
            categories={formState.categories}
            brands={formState.brands}
            attributes={formState.attributes}
            defaultCurrency={formState.defaultCurrency}
            isEditMode={isEditMode}
            loading={formState.loading}
            imageUploadLoading={formState.imageUploadLoading}
            imageUploadError={formState.imageUploadError}
            categoriesExpanded={formState.categoriesExpanded}
            brandsExpanded={formState.brandsExpanded}
            useNewCategory={formState.useNewCategory}
            useNewBrand={formState.useNewBrand}
            newCategoryName={formState.newCategoryName}
            newBrandName={formState.newBrandName}
            selectedAttributesForVariants={formState.selectedAttributesForVariants}
            selectedAttributeValueIds={formState.selectedAttributeValueIds}
            attributesDropdownOpen={formState.attributesDropdownOpen}
            generatedVariants={formState.generatedVariants}
            hasVariantsToLoad={formState.hasVariantsToLoad}
            fileInputRef={formState.fileInputRef}
            attributesDropdownRef={formState.attributesDropdownRef}
            variantImageInputRefs={formState.variantImageInputRefs}
            onTitleChange={handleTitleChange}
            onSlugChange={(e) => formState.setFormData((prev) => ({ ...prev, slug: e.target.value }))}
            onDescriptionChange={(e) => formState.setFormData((prev) => ({ ...prev, descriptionHtml: e.target.value }))}
            onProductTypeChange={formState.setProductType}
            onUploadImages={handleUploadImages}
            onRemoveImage={removeImageUrl}
            onSetFeaturedImage={setFeaturedImage}
            onCategoriesExpandedChange={formState.setCategoriesExpanded}
            onBrandsExpandedChange={formState.setBrandsExpanded}
            onUseNewCategoryChange={formState.setUseNewCategory}
            onUseNewBrandChange={formState.setUseNewBrand}
            onNewCategoryNameChange={formState.setNewCategoryName}
            onNewBrandNameChange={formState.setNewBrandName}
            onCategoryIdsChange={(ids) => formState.setFormData((prev) => ({ ...prev, categoryIds: ids }))}
            onBrandIdsChange={(ids) => formState.setFormData((prev) => ({ ...prev, brandIds: ids }))}
            onPrimaryCategoryIdChange={(id) => formState.setFormData((prev) => ({ ...prev, primaryCategoryId: id }))}
            onPriceChange={(value) => formState.setSimpleProductData((prev) => ({ ...prev, price: value }))}
            onCompareAtPriceChange={(value) => formState.setSimpleProductData((prev) => ({ ...prev, compareAtPrice: value }))}
            onSkuChange={(value) => formState.setSimpleProductData((prev) => ({ ...prev, sku: value }))}
            onQuantityChange={(value) => formState.setSimpleProductData((prev) => ({ ...prev, quantity: value }))}
            onAttributesDropdownToggle={() => formState.setAttributesDropdownOpen(!formState.attributesDropdownOpen)}
            onAttributeToggle={handleAttributeToggle}
            onAttributeRemove={handleAttributeRemove}
            onVariantUpdate={formState.setGeneratedVariants}
            onVariantDelete={handleVariantDelete}
            onVariantAdd={handleVariantAdd}
            onVariantImageUpload={(variantId, event) => handleUploadVariantImage(variantId, event)}
            onOpenValueModal={formState.setOpenValueModal}
            onAddLabel={addLabel}
            onRemoveLabel={removeLabel}
            onUpdateLabel={(index, field, value) => updateLabel(index, field, value)}
            onFeaturedChange={(featured) => formState.setFormData((prev) => ({ ...prev, featured }))}
            onVariantsUpdate={(updater) => formState.setFormData((prev) => ({ ...prev, variants: updater(prev.variants) }))}
            onApplyToAllVariants={(field, value) => applyToAllVariants(field, value)}
            isClothingCategory={isClothingCategory}
            generateSlug={generateSlug}
            handleSubmit={handleSubmit}
          />
        </div>
      </div>

      {formState.openValueModal && (
        <ValueSelectionModal
          openValueModal={formState.openValueModal}
          variant={formState.generatedVariants.find((v) => v.id === formState.openValueModal!.variantId)}
          attribute={formState.attributes.find((a) => a.id === formState.openValueModal!.attributeId)}
          selectedAttributeValueIds={formState.selectedAttributeValueIds}
          onClose={() => formState.setOpenValueModal(null)}
          onVariantUpdate={formState.setGeneratedVariants}
          onAttributeValueIdsUpdate={formState.setSelectedAttributeValueIds}
        />
      )}
    </div>
  );
}

export default function AddProductPage() {
