                    >
                      <span>{t('admin.products.product')}</span>
                      <span className="flex flex-col gap-0.5">
                        <svg
                          className={`w-2.5 h-2.5 ${
                            sortBy === 'title-asc'
                              ? 'text-gray-900'
                              : 'text-gray-400'
                          }`}
                          fill="none"
                          stroke="currentColor"
                          viewBox="0 0 24 24"
                        >
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 15l7-7 7 7" />
