'use client';

import Link from 'next/link';
import { usePathname } from 'next/navigation';
import { getStoredLanguage } from '../lib/language';
import { t } from '../lib/i18n';
import { useState, useEffect } from 'react';

interface BreadcrumbItem {
  label: string;
  href: string;
}

export function Breadcrumb() {
  const pathname = usePathname();
  const [language, setLanguage] = useState<'en' | 'ru' | 'hy' | 'ka'>('en');

  useEffect(() => {
    const storedLang = getStoredLanguage();
    setLanguage(storedLang);

    const handleLanguageUpdate = () => {
      setLanguage(getStoredLanguage());
    };

    window.addEventListener('language-updated', handleLanguageUpdate);
    return () => {
      window.removeEventListener('language-updated', handleLanguageUpdate);
    };
  }, []);

  const getBreadcrumbs = (): BreadcrumbItem[] => {
    const items: BreadcrumbItem[] = [
      { label: t(language, 'common.navigation.home'), href: '/' },
    ];

    if (pathname === '/') {
      return items;
    }

    const segments = pathname.split('/').filter(Boolean);

    segments.forEach((segment, index) => {
      const href = '/' + segments.slice(0, index + 1).join('/');
      
      // Translate common routes
      let label = segment;
      
      // Map common routes to translations
      const routeMap: Record<string, string> = {
        'products': 'common.navigation.products',
        'categories': 'common.navigation.categories',
        'cart': 'common.navigation.cart',
        'wishlist': 'common.navigation.wishlist',
        'compare': 'common.navigation.compare',
        'checkout': 'common.navigation.checkout',
        'profile': 'common.navigation.profile',
        'orders': 'common.navigation.orders',
        'login': 'common.navigation.login',
        'register': 'common.navigation.register',
        'about': 'common.navigation.about',
        'contact': 'common.navigation.contact',
        'admin': 'common.navigation.admin',
        'faq': 'common.navigation.faq',
        'shipping': 'common.navigation.shipping',
        'returns': 'common.navigation.returns',
        'support': 'common.navigation.support',
        'privacy': 'common.navigation.privacy',
        'terms': 'common.navigation.terms',
        'cookies': 'common.navigation.cookies',
        'delivery': 'common.navigation.delivery',
        'stores': 'common.navigation.stores',
      };

      if (routeMap[segment]) {
        label = t(language, routeMap[segment]);
      } else {
        // Capitalize and format segment (for product slugs, etc.)
        label = segment
          .split('-')
          .map(word => word.charAt(0).toUpperCase() + word.slice(1))
          .join(' ');
      }

      items.push({ label, href });
    });

    return items;
  };

  const breadcrumbs = getBreadcrumbs();

  // Don't show breadcrumb on home page
  if (pathname === '/') {
    return null;
  }

  return (
    <nav className="bg-gray-50 border-b border-gray-200">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-3">
        <div className="flex items-center text-sm">
          {breadcrumbs.map((item, index) => (
            <div key={item.href} className="flex items-center">
              {index > 0 && (
                <span className="mx-2 text-gray-400">/</span>
              )}
              {index === breadcrumbs.length - 1 ? (
                <span className="text-gray-900 font-semibold">{item.label}</span>
              ) : (
                <Link
                  href={item.href}
                  className="text-gray-500 hover:text-gray-700 transition-colors"
                >
                  {item.label}
                </Link>
              )}
            </div>
          ))}
        </div>
      </div>
    </nav>
  );
}

'use client';

import { Suspense, useEffect } from 'react';
import { useRouter, useSearchParams } from 'next/navigation';
import { useTranslation } from '../lib/i18n-client';
import { useCategories } from './CategoryNavigation/hooks/useCategories';
import { useCategoryProducts } from './CategoryNavigation/hooks/useCategoryProducts';
import { useCategoryScroll } from './CategoryNavigation/hooks/useCategoryScroll';
import { CategoryItem } from './CategoryNavigation/CategoryItem';
import { CategoryScrollButtons } from './CategoryNavigation/CategoryScrollButtons';
import { CategoryNavigationLoading } from './CategoryNavigation/CategoryNavigationLoading';
import type { Category } from './CategoryNavigation/utils';

function CategoryNavigationContent() {
  const router = useRouter();
  const searchParams = useSearchParams();
  const { t } = useTranslation();
  const currentCategory = searchParams?.get('category');
  
  const { categories, loading: categoriesLoading } = useCategories();
  const { categoryProducts, loading: productsLoading } = useCategoryProducts(categories, t);
  const {
    scrollContainerRef,
    canScrollLeft,
    canScrollRight,
    scrollByAmount,
    updateScrollButtons,
  } = useCategoryScroll();

  const loading = categoriesLoading || productsLoading;

  const handleCategoryClick = (categorySlug: string | null) => {
    const params = new URLSearchParams(searchParams?.toString() || '');
    
    if (categorySlug && categorySlug !== 'all') {
      params.set('category', categorySlug);
    } else {
      params.delete('category');
    }
    
    // Reset to page 1 when changing category
    params.delete('page');
    
    router.push(`/products?${params.toString()}`);
  };

  useEffect(() => {
    // Обновляем состояние кнопок после загрузки категорий и продуктов
    if (!loading && categories.length > 0) {
      setTimeout(() => {
        updateScrollButtons();
      }, 200);
    }
  }, [categories.length, Object.keys(categoryProducts).length, loading, updateScrollButtons]);

  if (loading) {
    return <CategoryNavigationLoading />;
  }

  // Add "All" category at the beginning
  const allCategoriesWithAll = [
    { id: 'all', slug: 'all', title: t('products.categoryNavigation.all'), fullPath: 'all', children: [] } as Category,
    ...categories
  ];

  // Limit to first 10 categories for horizontal navigation
  const displayCategories = allCategoriesWithAll.slice(0, 10);

  return (
    <div className="bg-white border-b border-gray-200 py-3 sm:py-4 md:py-6 w-full">
      <div className="max-w-7xl mx-auto px-2 sm:px-4 md:px-6 lg:px-8">
        <div className="relative">
          <CategoryScrollButtons
            canScrollLeft={canScrollLeft}
            canScrollRight={canScrollRight}
            onScrollLeft={() => scrollByAmount(-220)}
            onScrollRight={() => scrollByAmount(220)}
            t={t}
          />
          <div
            ref={scrollContainerRef}
            className="flex items-center gap-4 sm:gap-6 md:gap-8 overflow-x-auto scrollbar-hide pb-1 sm:pb-2 pl-2 sm:pl-4 md:pl-6"
            style={{ scrollBehavior: 'smooth' }}
          >
            {displayCategories.map((category) => {
              const isActive = category.slug === 'all' 
                ? !currentCategory 
                : currentCategory === category.slug;
              const product = categoryProducts[category.slug];

              return (
                <CategoryItem
                  key={category.id}
                  category={category}
                  product={product}
                  isActive={isActive}
                  currentCategory={currentCategory}
                  onCategoryClick={handleCategoryClick}
                  t={t}
                />
              );
            })}
          </div>
        </div>
      </div>
    </div>
  );
}

export function CategoryNavigation() {
  return (
    <Suspense fallback={<CategoryNavigationLoading />}>
      <CategoryNavigationContent />
    </Suspense>
  );
}

'use client';

import Link from 'next/link';
import { CategoryIcon } from './CategoryIcon';
import type { Category } from './utils';

interface Product {
  id: string;
  slug: string;
  title: string;
  image: string | null;
}

interface CategoryItemProps {
  category: Category;
  product: Product | null;
  isActive: boolean;
  currentCategory: string | null;
  onCategoryClick: (categorySlug: string | null) => void;
  t: (path: string) => string;
}

/**
 * Single category item component
 */
export function CategoryItem({
  category,
  product,
  isActive,
  currentCategory,
  onCategoryClick,
  t,
}: CategoryItemProps) {
  const title = category.title;
  const slug = category.slug;
  
  // Determine label text
  let labelText = title;
  if (slug === 'all') {
    labelText = t('products.categoryNavigation.shopAll');
  } else if (title.toLowerCase().includes('new')) {
    labelText = t('products.categoryNavigation.newArrivals');
  } else if (title.toLowerCase().includes('sale')) {
    labelText = t('products.categoryNavigation.sale');
  }

  return (
    <Link
      href={category.slug === 'all' ? '/products' : `/products?category=${category.slug}`}
      onClick={(e) => {
        e.preventDefault();
        onCategoryClick(category.slug === 'all' ? null : category.slug);
      }}
      className="flex flex-col items-center gap-1 sm:gap-2 min-w-[80px] sm:min-w-[100px] group cursor-pointer transition-all duration-200 hover:opacity-80"
    >
      {/* Category Icon/Image */}
      <div className="relative">
        <CategoryIcon
          category={category}
          product={product}
          isActive={isActive}
          t={t}
        />
      </div>
      
      {/* Category Label */}
      <span className={`text-[10px] sm:text-xs text-center font-medium leading-tight transition-colors ${
        isActive 
          ? 'text-gray-900 underline' 
          : 'text-gray-700'
      }`}>
        {labelText}
      </span>
    </Link>
  );
}

'use client';

import { useState, useEffect } from 'react';
import { useRouter, useSearchParams } from 'next/navigation';
import { Card } from '@shop/ui';
import { apiClient } from '../lib/api-client';
import { getStoredLanguage } from '../lib/language';
import { getColorHex } from '../lib/colorMap';
import { useTranslation } from '../lib/i18n-client';
import { useProductsFilters } from './ProductsFiltersProvider';

interface ColorFilterProps {
  category?: string;
  search?: string;
  minPrice?: string;
  maxPrice?: string;
  selectedColors?: string[];
}

export interface ColorOption {
  value: string;
  label: string;
  count: number;
  imageUrl?: string | null;
  colors?: string[] | null;
}

export function ColorFilter({ category, search, minPrice, maxPrice, selectedColors = [] }: ColorFilterProps) {
  const router = useRouter();
  const searchParams = useSearchParams();
  const filtersContext = useProductsFilters();
  const { t } = useTranslation();
  const [colors, setColors] = useState<ColorOption[]>([]);
  const [loading, setLoading] = useState(true);
  const [selected, setSelected] = useState<string[]>(selectedColors);

  useEffect(() => {
    if (filtersContext?.data?.colors) {
      setColors(filtersContext.data.colors);
      setLoading(false);
      return;
    }
    if (filtersContext === null) {
      fetchColors();
    } else {
      setLoading(filtersContext.loading);
    }
  }, [category, search, minPrice, maxPrice, filtersContext?.data?.colors, filtersContext?.loading, filtersContext === null]);

  useEffect(() => {
    setSelected(selectedColors);
  }, [selectedColors]);

  const fetchColors = async () => {
    try {
      setLoading(true);
      const language = getStoredLanguage();
      const params: Record<string, string> = {
        lang: language,
      };
      
      if (category) params.category = category;
      if (search) params.search = search;
      if (minPrice) params.minPrice = minPrice;
      if (maxPrice) params.maxPrice = maxPrice;

      // Fetch filters from API
      const response = await apiClient.get<{
        colors: ColorOption[];
        sizes: { value: string; count: number }[];
      }>('/api/v1/products/filters', { params });
      
      setColors(response.colors || []);
    } catch (error) {
      setColors([]);
    } finally {
      setLoading(false);
    }
  };

  const handleColorToggle = (colorValue: string) => {
    const newSelected = selected.includes(colorValue)
      ? selected.filter((c) => c !== colorValue)
      : [...selected, colorValue];

    setSelected(newSelected);
    applyFilters(newSelected);
  };

  const applyFilters = (colorsToApply: string[]) => {
    // Ստեղծում ենք նոր URLSearchParams URL-ի հիման վրա, որպեսզի պահպանենք բոլոր params-ները
    const params = new URLSearchParams(searchParams.toString());
    
    // Թարմացնում ենք colors պարամետրը
    if (colorsToApply.length > 0) {
      params.set('colors', colorsToApply.join(','));
    } else {
      params.delete('colors');
    }
    
    // Reset page to 1 when filters change
    params.delete('page');

    router.push(`/products?${params.toString()}`);
  };

  if (loading) {
    return (
      <Card className="p-4 mb-6">
        <h3 className="text-base font-bold text-gray-800 mb-4 uppercase tracking-wide">{t('products.filters.color.title')}</h3>
        <div className="text-sm text-gray-500">{t('products.filters.color.loading')}</div>
      </Card>
    );
  }

  return (
    <Card className="p-4 mb-6">
      <h3 className="text-base font-bold text-gray-800 mb-4 uppercase tracking-wide">{t('products.filters.color.title')}</h3>
      {colors.length === 0 ? (
        <div className="text-sm text-gray-500 py-4 text-center">
          {t('products.filters.color.noColors')}
        </div>
      ) : (
        <div className="space-y-2 max-h-64 overflow-y-auto">
          {colors.map((color) => {
            const isSelected = selected.includes(color.value);
            // Determine color hex: use colors[0] if available, otherwise use getColorHex
            const colorHex = color.colors && Array.isArray(color.colors) && color.colors.length > 0 
              ? color.colors[0] 
              : getColorHex(color.label);
            const hasImage = color.imageUrl && color.imageUrl.trim() !== '';

            return (
              <button
                key={color.value}
                type="button"
                onClick={() => handleColorToggle(color.value)}
                aria-pressed={isSelected}
                className={`w-full flex items-center justify-between py-2 px-1 rounded transition-colors group ${
                  isSelected
                    ? 'bg-blue-50 hover:bg-blue-100 border border-blue-200'
                    : 'hover:bg-gray-50'
                }`}
              >
                <div className="flex items-center gap-3">
                  <div
                    className={`w-4 h-4 rounded-full border flex-shrink-0 overflow-hidden ${
                      isSelected ? 'border-blue-500 border-2' : 'border-gray-300'
                    }`}
                    style={hasImage ? {} : { backgroundColor: colorHex }}
                    aria-label={color.label}
                  >
                    {hasImage ? (
                      <img 
                        src={color.imageUrl!} 
                        alt={color.label}
                        className="w-full h-full object-cover"
                        onError={(e) => {
                          // Fallback to color hex if image fails to load
                          (e.target as HTMLImageElement).style.backgroundColor = colorHex;
                          (e.target as HTMLImageElement).style.display = 'none';
                        }}
                      />
                    ) : null}
                  </div>
                  <span
                    className={`text-sm group-hover:text-gray-700 ${
                      isSelected ? 'text-blue-900 font-medium' : 'text-gray-900'
                    }`}
                  >
                    {color.label}
                  </span>
                </div>
                <span
                  className={`text-xs px-2 py-0.5 rounded-full ${
                    isSelected
                      ? 'text-blue-700 bg-blue-100'
                      : 'text-gray-500 bg-gray-100'
                  }`}
                >
                  {color.count}
                </span>
              </button>
            );
          })}
        </div>
      )}
    </Card>
  );
}

