'use client';

import { useState, useEffect } from 'react';
import { useRouter, useSearchParams } from 'next/navigation';
import { Card } from '@shop/ui';
import { apiClient } from '../lib/api-client';
import { getStoredLanguage } from '../lib/language';
import { useTranslation } from '../lib/i18n-client';
import { useProductsFilters } from './ProductsFiltersProvider';
import type { ColorOption } from './ColorFilter';

interface SizeFilterProps {
  category?: string;
  search?: string;
  minPrice?: string;
  maxPrice?: string;
  selectedSizes?: string[];
}

interface SizeOption {
  value: string;
  count: number;
}


export function SizeFilter({ category, search, minPrice, maxPrice, selectedSizes = [] }: SizeFilterProps) {
  const router = useRouter();
  const searchParams = useSearchParams();
  const filtersContext = useProductsFilters();
  const { t } = useTranslation();
  const [sizes, setSizes] = useState<SizeOption[]>([]);
  const [loading, setLoading] = useState(true);
  const [selected, setSelected] = useState<string[]>(selectedSizes);

  useEffect(() => {
    if (filtersContext?.data?.sizes) {
      setSizes(filtersContext.data.sizes);
      setLoading(false);
      return;
    }
    if (filtersContext === null) {
      fetchSizes();
    } else {
      setLoading(filtersContext.loading);
    }
  }, [category, search, minPrice, maxPrice, filtersContext?.data?.sizes, filtersContext?.loading, filtersContext === null]);

  useEffect(() => {
    setSelected(selectedSizes);
  }, [selectedSizes]);

  const fetchSizes = async () => {
    try {
      setLoading(true);
      const language = getStoredLanguage();
      const params: Record<string, string> = {
        lang: language,
      };
      
      if (category) params.category = category;
      if (search) params.search = search;
      if (minPrice) params.minPrice = minPrice;
      if (maxPrice) params.maxPrice = maxPrice;

      // Fetch filters from API
      const response = await apiClient.get<{ colors: ColorOption[]; sizes: SizeOption[] }>(
        '/api/v1/products/filters',
        { params }
      );
      
      setSizes(response.sizes || []);
    } catch (error) {
      setSizes([]);
    } finally {
      setLoading(false);
    }
  };

  const handleSizeToggle = (sizeValue: string) => {
    const newSelected = selected.includes(sizeValue)
      ? selected.filter((s) => s !== sizeValue)
      : [...selected, sizeValue];

    setSelected(newSelected);
    applyFilters(newSelected);
  };

  const applyFilters = (sizesToApply: string[]) => {
    // Ստեղծում ենք նոր URLSearchParams URL-ի հիման վրա, որպեսզի պահպանենք բոլոր params-ները
    const params = new URLSearchParams(searchParams.toString());
    
    // Թարմացնում ենք sizes պարամետրը
    if (sizesToApply.length > 0) {
      params.set('sizes', sizesToApply.join(','));
    } else {
      params.delete('sizes');
    }
    
    // Reset page to 1 when filters change
    params.delete('page');

    router.push(`/products?${params.toString()}`);
  };

  if (loading) {
    return (
      <Card className="p-4 mb-6">
        <h3 className="text-base font-bold text-gray-800 mb-4 uppercase tracking-wide">{t('products.filters.size.title')}</h3>
        <div className="text-sm text-gray-500">{t('products.filters.size.loading')}</div>
      </Card>
    );
  }

  return (
    <Card className="p-4 mb-6">
      <h3 className="text-base font-bold text-gray-800 mb-4 uppercase tracking-wide">{t('products.filters.size.title')}</h3>
      {sizes.length === 0 ? (
        <div className="text-sm text-gray-500 py-4 text-center">
          {t('products.filters.size.noSizes')}
        </div>
      ) : (
        <div className="space-y-2 max-h-64 overflow-y-auto">
          {sizes.map((size) => {
            const isSelected = selected.includes(size.value);

            return (
              <button
                key={size.value}
                onClick={() => handleSizeToggle(size.value)}
                className={`w-full flex items-center justify-between py-2 px-1 rounded transition-colors group ${
                  isSelected
                    ? 'bg-blue-50 hover:bg-blue-100 border border-blue-200'
                    : 'hover:bg-gray-50'
                }`}
              >
                <span
                  className={`text-sm group-hover:text-gray-700 ${
                    isSelected ? 'text-blue-900 font-medium' : 'text-gray-900'
                  }`}
                >
                  {size.value}
                </span>
                <span
                  className={`text-xs px-2 py-0.5 rounded-full ${
                    isSelected
                      ? 'text-blue-700 bg-blue-100'
                      : 'text-gray-500 bg-gray-100'
                  }`}
                >
                  {size.count}
                </span>
              </button>
            );
          })}
        </div>
      )}
    </Card>
  );
}

'use client';

import { logger } from '@/lib/utils/logger';
import { useState, useEffect } from 'react';
import { apiClient } from '../../lib/api-client';
import { getStoredLanguage, type LanguageCode } from '../../lib/language';

interface RelatedProduct {
  id: string;
  slug: string;
  title: string;
  price: number;
  originalPrice?: number | null;
  compareAtPrice: number | null;
  discountPercent?: number | null;
  image: string | null;
  inStock: boolean;
  brand?: {
    id: string;
    name: string;
  } | null;
  categories?: Array<{
    id: string;
    slug: string;
    title: string;
  }>;
  variants?: Array<{
    options?: Array<{
      key: string;
      value: string;
    }>;
  }>;
}

interface UseRelatedProductsProps {
  categorySlug?: string;
  currentProductId: string;
  language: LanguageCode;
}

/**
 * Hook for fetching related products
 */
export function useRelatedProducts({ categorySlug, currentProductId, language }: UseRelatedProductsProps) {
  const [products, setProducts] = useState<RelatedProduct[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchRelatedProducts = async () => {
      try {
        setLoading(true);
        
        // Build params - if no categorySlug, fetch all products
        const params: Record<string, string> = {
          limit: '30', // Fetch more to ensure we have 10 after filtering
          lang: language,
        };
        
        if (categorySlug) {
          params.category = categorySlug;
          logger.debug('[RelatedProducts] Fetching related products for category:', categorySlug);
        } else {
          logger.debug('[RelatedProducts] No categorySlug, fetching all products');
        }
        
        const response = await apiClient.get<{
          data: RelatedProduct[];
          meta: {
            total: number;
          };
        }>('/api/v1/products', {
          params,
        });

        logger.debug('[RelatedProducts] Received products:', response.data.length);
        // Filter out current product and take exactly 10
        const filtered = response.data.filter(p => p.id !== currentProductId);
        logger.debug('[RelatedProducts] After filtering current product:', filtered.length);
        const finalProducts = filtered.slice(0, 10);
        logger.debug('[RelatedProducts] Final products to display:', finalProducts.length);
        setProducts(finalProducts);
      } catch (error) {
        console.error('[RelatedProducts] Error fetching related products:', error);
        setProducts([]);
      } finally {
        setLoading(false);
      }
    };

    fetchRelatedProducts();
  }, [categorySlug, currentProductId, language]);

  return { products, loading };
}

import { logger } from '@/lib/utils/logger';
import { ApiError } from "./types";
import type { RequestOptions } from "./types";
import { buildUrl } from "./url-builder";
import { getHeaders } from "./headers";
import { handleUnauthorized } from "./auth-utils";
import { shouldLogError, shouldLogWarning, parseErrorResponse, createApiError } from "./error-handler";

/**
 * Handle network errors
 */
function handleNetworkError(error: unknown, baseUrl: string, url: string): never {
  const networkError = error as { message?: string; name?: string };
  
  // Check if it's a timeout error
  if (networkError.message?.includes('timeout') || networkError.message?.includes('Request timeout')) {
    console.error('⏱️ [API CLIENT] Request timeout:', networkError.message);
    throw networkError;
  }
  
  console.error('❌ [API CLIENT] Network error during fetch:', networkError);
  
  // Check if it's a connection refused error
  const isConnectionRefused = 
    networkError.message?.includes('Failed to fetch') || 
    networkError.message?.includes('ERR_CONNECTION_REFUSED') ||
    networkError.message?.includes('NetworkError') ||
    networkError.message?.includes('Network request failed');
  
  if (isConnectionRefused) {
    const errorMessage = baseUrl 
      ? `⚠️ API սերվերը հասանելի չէ!\n\n` +
        `Չհաջողվեց միանալ ${baseUrl}\n\n` +
        `Լուծում:\n` +
        `1. Համոզվեք, որ API սերվերը գործարկված է\n` +
        `2. Ստուգեք, որ ${baseUrl.split(':').pop() || 'port'} պորտը զբաղված չէ այլ գործընթացով\n\n` +
        `Հարցման URL: ${url}`
      : `⚠️ API route-ը հասանելի չէ!\n\n` +
        `Չհաջողվեց միանալ Next.js API route-ին: ${url}\n\n` +
        `Լուծում:\n` +
        `1. Համոզվեք, որ Next.js dev server-ը գործարկված է (npm run dev)\n` +
        `2. Ստուգեք, որ API route-ը գոյություն ունի: ${url}\n\n`;
    
    console.error('❌ [API CLIENT]', errorMessage);
    throw new Error(errorMessage);
  }
  
  throw new Error(`Ցանցային սխալ: Չհաջողվեց միանալ API-ին ${url}. ${networkError.message || 'Խնդրում ենք ստուգել, արդյոք Next.js server-ը գործարկված է:'}`);
}

/**
 * Handle error response
 */
async function handleErrorResponse(
  response: Response,
  url: string,
  baseUrl: string
): Promise<never> {
  const isUnauthorized = response.status === 401;
  const isNotFound = response.status === 404;
  
  // Log 404 as warning (expected situation - resource doesn't exist)
  if (shouldLogWarning(response.status)) {
    console.warn(`⚠️ [API CLIENT] Not Found (404): ${url}`);
  }
  // Log other errors (except 401 which is expected)
  else if (shouldLogError(response.status)) {
    console.error(`❌ [API CLIENT] Error: ${response.status} ${response.statusText}`, {
      url,
      status: response.status,
      statusText: response.statusText,
      headers: Object.fromEntries(response.headers.entries()),
    });
  }
  
  // Handle 401 Unauthorized - clear token and redirect
  if (isUnauthorized) {
    handleUnauthorized();
  }
  
  const { errorText, errorData } = await parseErrorResponse(response);
  
  // Log error details
  if (isNotFound) {
    console.warn('⚠️ [API CLIENT] Not Found response:', errorData || errorText);
  } else if (!isUnauthorized && shouldLogError(response.status)) {
    console.error('❌ [API CLIENT] Error response:', errorData || errorText);
  }
  
  throw createApiError(response, errorText, errorData);
}

/**
 * GET request
 */
export async function getRequest<T>(
  baseUrl: string,
  endpoint: string,
  options?: RequestOptions,
  retryCount = 0
): Promise<T> {
  const url = buildUrl(baseUrl, endpoint, options?.params);
  const maxRetries = 3;
  const retryDelay = 1000; // 1 second
  const timeout = 30000; // 30 seconds timeout
  
  logger.debug('🌐 [API CLIENT] GET request:', { url, endpoint, baseUrl });
  
  let response: Response;
  try {
    // Create timeout controller
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), timeout);
    
    try {
      response = await fetch(url, {
        method: 'GET',
        headers: getHeaders(options),
        cache: 'no-store', // Disable caching for server components
        signal: controller.signal,
        ...options,
      });
      clearTimeout(timeoutId);
    } catch (fetchError: unknown) {
      clearTimeout(timeoutId);
      const error = fetchError as { name?: string };
      if (error.name === 'AbortError') {
        throw new Error(`Request timeout: API server did not respond within ${timeout / 1000} seconds. URL: ${url}`);
      }
      throw fetchError;
    }
    
    // Log response status safely
    try {
      logger.debug('🌐 [API CLIENT] GET response status:', response.status, response.statusText || '');
    } catch {
      console.warn('⚠️ [API CLIENT] Failed to log response status');
    }
  } catch (networkError: unknown) {
    handleNetworkError(networkError, baseUrl, url);
  }

  if (!response.ok) {
    // Retry on 429 (Too Many Requests) errors
    if (response.status === 429 && retryCount < maxRetries) {
      const delay = retryDelay * (retryCount + 1); // Exponential backoff
      console.warn(`⚠️ [API CLIENT] Rate limited, retrying in ${delay}ms... (attempt ${retryCount + 1}/${maxRetries})`);
      await new Promise(resolve => setTimeout(resolve, delay));
      return getRequest<T>(baseUrl, endpoint, options, retryCount + 1);
    }

    await handleErrorResponse(response, url, baseUrl);
  }

  try {
    if (!response) {
      throw new Error('Response is undefined');
    }

    const contentType = response.headers?.get('content-type');
    logger.debug('🌐 [API CLIENT] Response content-type:', contentType);
    
    if (!contentType || !contentType.includes('application/json')) {
      const text = await response.text();
      console.error('❌ [API CLIENT] GET Non-JSON response:', {
        contentType,
        status: response.status,
        text: text?.substring(0, 200) || '', // First 200 chars
      });
      throw new Error(`Expected JSON response but got ${contentType}. Status: ${response.status}`);
    }
    
    const jsonData = await response.json();
    logger.debug('✅ [API CLIENT] GET Response parsed successfully');
    
    if (!jsonData) {
      console.warn('⚠️ [API CLIENT] Response data is null or undefined');
      return null as T;
    }
    
    return jsonData;
  } catch (parseError: unknown) {
    const error = parseError as { message?: string; stack?: string };
    console.error('❌ [API CLIENT] GET JSON parse error:', parseError);
    console.error('❌ [API CLIENT] Parse error stack:', error.stack);
    if (error.message && error.message.includes('Expected JSON')) {
      throw parseError;
    }
    throw new Error(`Failed to parse response as JSON: ${error.message || String(parseError)}`);
  }
}

/**
 * POST request
 */
export async function postRequest<T>(
  baseUrl: string,
  endpoint: string,
  data?: unknown,
  options?: RequestOptions
): Promise<T> {
  try {
    const url = buildUrl(baseUrl, endpoint, options?.params);
    
    logger.debug('📤 [API CLIENT] POST request:', { url, data: data ? 'provided' : 'none' });
    
    const response = await fetch(url, {
      method: 'POST',
      headers: getHeaders(options),
      body: data ? JSON.stringify(data) : undefined,
      ...options,
    });

    logger.debug('📥 [API CLIENT] Response status:', response.status, response.statusText);

    if (!response.ok) {
      const isUnauthorized = response.status === 401;
      
      // Handle 401 Unauthorized - clear token and redirect
      if (isUnauthorized) {
        handleUnauthorized();
      }
      
      await handleErrorResponse(response, url, baseUrl);
    }

    try {
      const jsonData = await response.json();
      logger.debug('✅ [API CLIENT] Response parsed successfully');
      return jsonData;
    } catch (parseError: unknown) {
      console.error('❌ [API CLIENT] JSON parse error:', parseError);
      throw new Error(`Failed to parse response: ${String(parseError)}`);
    }
  } catch (error: unknown) {
    // Handle network errors, URL construction errors, etc.
    if (error instanceof TypeError && error.message.includes('fetch')) {
      console.error('❌ [API CLIENT] Network error:', error);
      const errorMsg = baseUrl
        ? `Network error: Unable to connect to API. Please check if the API server is running at ${baseUrl}`
        : `Network error: Unable to connect to Next.js API routes. Please check if the Next.js server is running.`;
      throw new Error(errorMsg);
    }
    
    // Re-throw if it's already our custom ApiError
    if (error instanceof ApiError) {
      throw error;
    }
    
    // Re-throw if it's a parse error
    const errorObj = error as { message?: string };
    if (errorObj.message && errorObj.message.includes('Failed to parse')) {
      throw error;
    }
    
    // Otherwise wrap in a generic error
    console.error('❌ [API CLIENT] POST request failed:', error);
    throw new Error(`API request failed: ${errorObj.message || String(error)}`);
  }
}

/**
 * PUT request
 */
export async function putRequest<T>(
  baseUrl: string,
  endpoint: string,
  data?: unknown,
  options?: RequestOptions
): Promise<T> {
  const url = buildUrl(baseUrl, endpoint, options?.params);
  
  logger.debug('📤 [API CLIENT] PUT request:', { url, endpoint, hasData: !!data });
  
  const response = await fetch(url, {
    method: 'PUT',
    headers: getHeaders(options),
    body: data ? JSON.stringify(data) : undefined,
    ...options,
  });

  logger.debug('📥 [API CLIENT] PUT response status:', response.status, response.statusText);

  if (!response.ok) {
    await handleErrorResponse(response, url, baseUrl);
  }

  try {
    const jsonData = await response.json();
    logger.debug('✅ [API CLIENT] PUT Response parsed successfully');
    return jsonData;
  } catch (parseError: unknown) {
    console.error('❌ [API CLIENT] PUT JSON parse error:', {
      url,
      status: response.status,
      error: parseError,
    });
    throw new Error(`Failed to parse response: ${String(parseError)}`);
  }
}

/**
 * PATCH request
 */
export async function patchRequest<T>(
  baseUrl: string,
  endpoint: string,
  data?: unknown,
  options?: RequestOptions
): Promise<T> {
  const url = buildUrl(baseUrl, endpoint, options?.params);
  
  const response = await fetch(url, {
    method: 'PATCH',
    headers: getHeaders(options),
    body: data ? JSON.stringify(data) : undefined,
    ...options,
  });

  if (!response.ok) {
    await handleErrorResponse(response, url, baseUrl);
  }

  try {
    return await response.json();
  } catch (parseError: unknown) {
    console.error('❌ [API CLIENT] PATCH JSON parse error:', parseError);
    throw new Error(`Failed to parse response: ${String(parseError)}`);
  }
}

/**
 * DELETE request
 */
export async function deleteRequest<T>(
  baseUrl: string,
  endpoint: string,
  options?: RequestOptions
): Promise<T> {
  const url = buildUrl(baseUrl, endpoint, options?.params);
  
  const response = await fetch(url, {
    method: 'DELETE',
    headers: getHeaders(options),
    ...options,
  });

  if (!response.ok) {
    await handleErrorResponse(response, url, baseUrl);
  }

  // DELETE requests might not return a body
  try {
    const text = await response.text();
    if (text) {
      return JSON.parse(text);
    }
    return null as T;
  } catch {
    // If there's no body or parse fails, return null for DELETE
    return null as T;
  }
}

import type { RequestOptions } from "./types";

/**
 * Build URL from endpoint and params
 */
export function buildUrl(
  baseUrl: string,
  endpoint: string,
  params?: Record<string, string>
): string {
  // Ensure endpoint starts with /
  const normalizedEndpoint = endpoint.startsWith('/') ? endpoint : `/${endpoint}`;
  
  // If baseUrl is empty (relative paths for Next.js API routes)
  if (!baseUrl || baseUrl.trim() === '') {
    // Check if we're on the server (Node.js environment)
    const isServer = typeof window === 'undefined';
    
    // On server, we need an absolute URL
    if (isServer) {
      // Try to get the base URL from environment variable or construct it
      let serverUrl = process.env.NEXT_PUBLIC_APP_URL;
      if (!serverUrl) {
        if (process.env.VERCEL_URL) {
          serverUrl = `https://${process.env.VERCEL_URL}`;
        } else {
          serverUrl = 'http://localhost:3000';
        }
      }
      
      let url = `${serverUrl}${normalizedEndpoint}`;
      if (params && Object.keys(params).length > 0) {
        const searchParams = Object.entries(params)
          .filter(([_, value]) => value !== undefined && value !== null)
          .map(([key, value]) => `${encodeURIComponent(key)}=${encodeURIComponent(String(value))}`)
          .join('&');
        url = `${url}${url.includes('?') ? '&' : '?'}${searchParams}`;
      }
      return url;
    }
    
    // On client, use relative URL
    let url = normalizedEndpoint;
    if (params && Object.keys(params).length > 0) {
      const searchParams = Object.entries(params)
        .filter(([_, value]) => value !== undefined && value !== null)
        .map(([key, value]) => `${encodeURIComponent(key)}=${encodeURIComponent(String(value))}`)
        .join('&');
      url = `${url}${url.includes('?') ? '&' : '?'}${searchParams}`;
    }
    return url;
  }
  
  // Build base URL for absolute URLs
  let normalizedBaseUrl = baseUrl;
  if (!normalizedBaseUrl.endsWith('/')) {
    normalizedBaseUrl = normalizedBaseUrl.replace(/\/+$/, '');
  }
  
  // Combine base URL and endpoint
  const fullUrl = `${normalizedBaseUrl}${normalizedEndpoint}`;
  
  // Use URL constructor for proper URL handling
  try {
    const url = new URL(fullUrl);
    
    if (params) {
      Object.entries(params).forEach(([key, value]) => {
        if (value !== undefined && value !== null) {
          url.searchParams.append(key, String(value));
        }
      });
    }
    
    return url.toString();
  } catch (error) {
    // Fallback: manual URL construction if URL constructor fails
    console.error('❌ [API CLIENT] URL construction error:', error, { baseUrl, endpoint, fullUrl });
    
    let url = fullUrl;
    if (params && Object.keys(params).length > 0) {
      const searchParams = Object.entries(params)
        .filter(([_, value]) => value !== undefined && value !== null)
        .map(([key, value]) => `${encodeURIComponent(key)}=${encodeURIComponent(String(value))}`)
        .join('&');
      url = `${url}${url.includes('?') ? '&' : '?'}${searchParams}`;
    }
    
    return url;
  }
}

